import { GoogleGenAI, Type } from "@google/genai";
import { BrandDNA, Campaign, UserInput, Asset } from "./types";

// Standard AI for general tasks
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeBrandDNA = async (input: UserInput): Promise<BrandDNA> => {
  const prompt = `Analyze this business and extract its "Business DNA" for branding. 
  Business: ${input.businessName}
  URL: ${input.url}
  Description: ${input.description}
  Location: ${input.country}

  Focus on African cultural context (e.g., color palettes inspired by local textiles like Bogolan, Kente, or modern urban African aesthetics).

  Return valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          colors: { type: Type.ARRAY, items: { type: Type.STRING } },
          fonts: { type: Type.ARRAY, items: { type: Type.STRING } },
          tone: { type: Type.STRING },
          imageStyle: { type: Type.STRING },
          keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          localContext: { type: Type.STRING }
        },
        required: ["name", "colors", "fonts", "tone", "imageStyle", "keywords", "localContext"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateCampaigns = async (dna: BrandDNA, input: UserInput): Promise<Campaign[]> => {
  const prompt = `Generate 3 culturally relevant social media campaign ideas for ${dna.name} in ${input.country}.
  Target Audience: ${input.targetAudience}
  Business Tone: ${dna.tone}
  Keywords: ${dna.keywords.join(', ')}

  The ideas must incorporate African cultural nuances. 
  Also provide a short video script (30 words max) for a 6-second promo.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            concept: { type: Type.STRING },
            culturalHook: { type: Type.STRING },
            cta: { type: Type.STRING },
            suggestedPlatforms: { type: Type.ARRAY, items: { type: Type.STRING } },
            videoScript: { type: Type.STRING }
          },
          required: ["id", "title", "concept", "culturalHook", "cta", "suggestedPlatforms", "videoScript"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
};

export const generateAssetVisual = async (campaign: Campaign, dna: BrandDNA, assetType: string): Promise<string> => {
  const prompt = `A high-quality commercial social media ${assetType} image for ${dna.name}.
  Visual Style: ${dna.imageStyle}.
  Concept: ${campaign.concept}.
  Incorporate: ${dna.localContext}.
  Color Palette: ${dna.colors.join(', ')}.
  Aesthetic: Modern African, clean, vibrant. Avoid stereotypes.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: assetType === 'story' ? '9:16' : '1:1' }
    }
  });

  let imageUrl = '';
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      break;
    }
  }
  return imageUrl;
};

export const generateVideoAd = async (campaign: Campaign, dna: BrandDNA): Promise<string> => {
  // Use a fresh instance right before Veo call as required
  const veoAi = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  const prompt = `A cinematic social media marketing video for ${dna.name}. 
  Style: ${dna.imageStyle}. 
  Action: ${campaign.videoScript}. 
  Atmosphere: Vibrant, African modern luxury. 
  Palette: ${dna.colors.join(', ')}.`;

  let operation = await veoAi.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 5000));
    operation = await veoAi.operations.getVideosOperation({ operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await response.blob();
  return URL.createObjectURL(blob);
};

export const generateAssetContent = async (campaign: Campaign, dna: BrandDNA, language: string): Promise<{ headline: string, caption: string }> => {
  const prompt = `Write a headline and a social media caption for this campaign:
  Campaign: ${campaign.title}
  CTA: ${campaign.cta}
  Language: ${language}
  Tone: ${dna.tone}
  Include 5 relevant local hashtags.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING },
          caption: { type: Type.STRING }
        },
        required: ["headline", "caption"]
      }
    }
  });

  return JSON.parse(response.text || '{"headline": "", "caption": ""}');
};

export const editAssetWithNL = async (asset: Asset, command: string, dna: BrandDNA): Promise<Asset> => {
  const prompt = `The user wants to edit a marketing asset.
  Original Headline: ${asset.headline}
  Original Caption: ${asset.caption}
  User Command: ${command}
  DNA Context: ${dna.tone}

  Apply the change and return updated headline and caption.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING },
          caption: { type: Type.STRING }
        },
        required: ["headline", "caption"]
      }
    }
  });

  const results = JSON.parse(response.text || '{}');
  return { ...asset, ...results };
};

import React, { useState } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset } from './types';
import * as aiService from './geminiService';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('welcome');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Young entrepreneurs',
    preferredLanguages: ['French', 'Wolof']
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage('Decoding your brand DNA...');
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Please check your inputs or API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage('Exploring local cultural hooks...');
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage('Creating on-brand visual assets...');
    try {
      const type = 'post';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, type);
      const content = await aiService.generateAssetContent(campaign, dna, userInput.preferredLanguages[0]);

      const newAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'post',
        imageUrl,
        headline: content.headline,
        caption: content.caption,
        language: userInput.preferredLanguages[0]
      };

      setAssets([newAsset]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async () => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage('Directing your 6-second cinematic promo...');
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna);
      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Video promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0]
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
      // @ts-ignore
      if (error?.message?.includes('Requested entity was not found')) {
        // @ts-ignore
        await window.aistudio.openSelectKey();
      }
    } finally {
      setLoading(false);
    }
  };

  const openEditor = (asset: Asset) => {
    setSelectedAsset(asset);
    setStep('editor');
  };

  const updateAsset = (updated: Asset) => {
    setAssets(prev => prev.map(a => a.id === updated.id ? updated : a));
    setSelectedAsset(updated);
  };

  return (
    <div className="min-h-screen gradient-bg text-slate-900">
      <header className="p-4 glass sticky top-0 z-50 flex justify-between items-center shadow-sm">
        <div className="flex items-center gap-2">
          <div className="w-10 h-10 bg-amber-600 rounded-lg flex items-center justify-center text-white font-bold text-xl">A</div>
          <h1 className="text-xl font-bold tracking-tight">AfriBrand <span className="text-amber-600">AI</span></h1>
        </div>
        {step !== 'welcome' && (
          <button 
            onClick={() => setStep('welcome')}
            className="text-sm font-medium text-slate-500 hover:text-slate-900 px-3 py-1 bg-slate-100 rounded-full"
          >
            New Brand
          </button>
        )}
      </header>

      <main className="max-w-4xl mx-auto p-4 pb-24">
        {loading && (
          <div className="fixed inset-0 bg-white/70 backdrop-blur-md z-[100] flex flex-col items-center justify-center text-center p-6">
            <div className="w-20 h-20 border-4 border-amber-600 border-t-transparent rounded-full animate-spin mb-6"></div>
            <h3 className="text-2xl font-bold text-slate-800">{loadingMessage}</h3>
            <p className="text-slate-500 mt-2 max-w-xs">Our AI is mixing cultural heritage with modern tech. This might take a moment.</p>
          </div>
        )}

        {step === 'welcome' && <Welcome onStart={startAnalysis} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} onSelect={generateCampaignAssets} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            onEdit={openEditor} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={updateAsset} 
            onBack={() => setStep('assets')}
          />
        )}
      </main>

      <footer className="fixed bottom-0 left-0 right-0 p-4 glass border-t border-slate-200 text-center text-xs text-slate-400">
        &copy; 2025 AfriBrand AI • Optimized for African PMEs • PWA Enabled
      </footer>
    </div>
  );
};

