import { GoogleGenAI, Type } from "@google/genai";
import { BrandDNA, Campaign, UserInput, Asset } from "./types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeBrandDNA = async (input: UserInput): Promise<BrandDNA> => {
  const prompt = `Act as a world-class brand strategist specialized in the African market. 
  Analyze this business: ${input.businessName} (URL: ${input.url}). 
  Description: ${input.description}. Location: ${input.country}.

  Extract a "Business DNA" that fuses modern professional branding with high-end African aesthetic markers (e.g. textures inspired by Bogolan, Kente, Aso-Oke, or modern metropolitan African minimalism).

  Return valid JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          colors: { type: Type.ARRAY, items: { type: Type.STRING } },
          fonts: { type: Type.ARRAY, items: { type: Type.STRING } },
          tone: { type: Type.STRING },
          imageStyle: { type: Type.STRING },
          keywords: { type: Type.ARRAY, items: { type: Type.STRING } },
          localContext: { type: Type.STRING }
        },
        required: ["name", "colors", "fonts", "tone", "imageStyle", "keywords", "localContext"]
      }
    }
  });

  return JSON.parse(response.text || '{}');
};

export const generateCampaigns = async (dna: BrandDNA, input: UserInput): Promise<Campaign[]> => {
  const prompt = `Generate 3 high-impact marketing campaign ideas for ${dna.name} in ${input.country}.
  Audience: ${input.targetAudience}. Tone: ${dna.tone}.

  Localization requirement: Use deep regional cultural hooks (e.g. specific slang like 'Chale', 'Sawa', or 'Nawa', local holidays, or market behaviors). 
  The campaigns should feel "high-end" and ultra-professional. 
  Assign a scheduledDate for each (YYYY-MM-DD format starting from today).`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            id: { type: Type.STRING },
            title: { type: Type.STRING },
            concept: { type: Type.STRING },
            culturalHook: { type: Type.STRING },
            cta: { type: Type.STRING },
            suggestedPlatforms: { type: Type.ARRAY, items: { type: Type.STRING } },
            videoScript: { type: Type.STRING },
            scheduledDate: { type: Type.STRING }
          },
          required: ["id", "title", "concept", "culturalHook", "cta", "suggestedPlatforms", "videoScript", "scheduledDate"]
        }
      }
    }
  });

  return JSON.parse(response.text || '[]');
};

export const generateAssetVisual = async (campaign: Campaign, dna: BrandDNA, assetType: string): Promise<string> => {
  const prompt = `Professional high-end commercial photography for ${dna.name}. 
  Context: ${campaign.concept}. 
  Style: ${dna.imageStyle}, luxury aesthetic, vibrant but tasteful colors (${dna.colors.join(', ')}). 
  Setting: Authentic ${dna.localContext} environment, modern lighting, 8k resolution. No generic stock photo looks. Avoid stereotypes.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: { aspectRatio: assetType === 'story' ? '9:16' : '1:1' }
    }
  });

  let imageUrl = '';
  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      imageUrl = `data:image/png;base64,${part.inlineData.data}`;
      break;
    }
  }
  return imageUrl;
};

export const generateAssetContent = async (campaign: Campaign, dna: BrandDNA, language: string): Promise<{ headline: string, caption: string }> => {
  const prompt = `Write high-converting marketing copy.
  Campaign: ${campaign.title}. 
  Language: ${language}.
  Tone: ${dna.tone}.
  Inject subtle local slang and cultural nuances that build trust in the ${dna.localContext} region.
  Format as JSON.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING },
          caption: { type: Type.STRING }
        },
        required: ["headline", "caption"]
      }
    }
  });

  return JSON.parse(response.text || '{"headline": "", "caption": ""}');
};

export const editAssetWithNL = async (asset: Asset, command: string, dna: BrandDNA): Promise<Asset> => {
  const prompt = `Refine the marketing copy based on this request: "${command}".
  Current Headline: ${asset.headline}.
  Current Caption: ${asset.caption}.
  Context: ${dna.tone}, targeting African local market.
  Maintain high-end brand standards.`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          headline: { type: Type.STRING },
          caption: { type: Type.STRING }
        },
        required: ["headline", "caption"]
      }
    }
  });

  const results = JSON.parse(response.text || '{}');
  return { ...asset, ...results };
};

import React, { useState } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset } from './types';
import * as aiService from './geminiService';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('welcome');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Young entrepreneurs',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage('Strategizing with Cultural Intelligence...');
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage('Curating Local Cultural Hooks...');
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage('Generating High-End Visuals...');
    try {
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post');
      const content = await aiService.generateAssetContent(campaign, dna, userInput.preferredLanguages[0]);

      const newAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'post',
        imageUrl,
        headline: content.headline,
        caption: content.caption,
        language: userInput.preferredLanguages[0]
      };

      setAssets([newAsset]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async () => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage('Producing Cinematic Motion Promo...');
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna);
      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0]
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen gradient-bg text-slate-900 selection:bg-amber-200">
      <header className="px-6 py-4 glass sticky top-0 z-50 flex justify-between items-center shadow-lg border-b border-white/20">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-amber-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
             <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tight leading-none">AfriBrand <span className="text-amber-600">AI</span></h1>
            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Premium Marketing Suite</p>
          </div>
        </div>
        <div className="flex gap-4">
            {step === 'assets' && (
                <button 
                    onClick={() => setStep('calendar')}
                    className="px-4 py-2 bg-white/50 hover:bg-white text-slate-700 rounded-xl text-xs font-bold border border-slate-200 transition-all flex items-center gap-2"
                >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                    Campaign Calendar
                </button>
            )}
            {step !== 'welcome' && (
              <button 
                onClick={() => setStep('welcome')}
                className="px-4 py-2 bg-amber-600 text-white rounded-xl text-xs font-bold shadow-lg shadow-amber-600/20 hover:bg-amber-700 transition-all"
              >
                Reset Session
              </button>
            )}
        </div>
      </header>

      <main className="max-w-6xl mx-auto p-6">
        {loading && (
          <div className="fixed inset-0 bg-white/80 backdrop-blur-xl z-[100] flex flex-col items-center justify-center text-center p-8">
            <div className="relative">
                <div className="w-24 h-24 border-4 border-amber-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center font-bold text-amber-600">A</div>
            </div>
            <h3 className="text-3xl font-black text-slate-800 mt-8 mb-2">{loadingMessage}</h3>
            <p className="text-slate-500 max-w-sm">Crafting bespoke African brand narratives. This precision takes a moment.</p>
          </div>
        )}

        {step === 'welcome' && <Welcome onStart={startAnalysis} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} onSelect={generateCampaignAssets} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>
    </div>
  );
};

export default App;

