  onBack: () => void;
}

const CalendarView: React.FC<CalendarViewProps> = ({ campaigns, onBack }) => {
  const downloadCSV = () => {
    const headers = ['Title', 'Concept', 'Scheduled Date', 'Cultural Hook', 'Platforms'];
    const rows = campaigns.map(c => [
      c.title,
      c.concept.replace(/,/g, ''),
      c.scheduledDate,
      c.culturalHook,
      c.suggestedPlatforms.join(';')
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + [headers, ...rows].map(e => e.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "afribrand_calendar.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const downloadICS = () => {
    let icsContent = "BEGIN:VCALENDAR\nVERSION:2.0\nPRODID:-//AfriBrand AI//Editorial Calendar//EN\n";
    campaigns.forEach(c => {
      const date = c.scheduledDate?.replace(/-/g, '') || '';
      icsContent += `BEGIN:VEVENT\nSUMMARY:${c.title}\nDTSTART:${date}T100000Z\nDESCRIPTION:${c.concept}\nEND:VEVENT\n`;
    });
    icsContent += "END:VCALENDAR";

    const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
    const link = document.createElement('a');
    link.href = window.URL.createObjectURL(blob);
    link.setAttribute('download', 'afribrand_calendar.ics');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
