/**
 * Produces a cinematic video advertisement using veo-3.1-fast-generate-preview.
 * Handles operation polling and secure asset fetching with process.env.API_KEY.
 */
export const generateVideoAd = async (campaign: Campaign, dna: BrandDNA): Promise<string> => {
  // Create a new GoogleGenAI instance right before making an API call for Veo models.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const prompt = `A cinematic, high-end professional promotional video for ${dna.name}. 
  Concept: ${campaign.concept}. 
  Atmosphere: Local ${dna.localContext} market environment with a luxury, modern metropolitan aesthetic. 
  Vibrant but tasteful colors: ${dna.colors.join(', ')}.`;

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: '9:16'
    }
  });

  // Poll the operation until completion.
  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed or timed out.");

  // Fetching the video from the download link requires appending the API key.
  const fetchResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  if (!fetchResponse.ok) throw new Error(`Failed to download video: ${fetchResponse.statusText}`);

  const blob = await fetchResponse.blob();
  return URL.createObjectURL(blob);
};

