    { id: 'professional', label: 'Pro Studio', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 13.255A23.931 23.931 0 0112 15c-3.183 0-6.22-.62-9-1.745M16 6V4a2 2 0 00-2-2h-4a2 2 0 00-2 2v2m4 6h.01M5 20h14a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v10a2 2 0 002 2z"></path></svg> },
    { id: 'anime', label: 'Anime', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 3v4M3 5h4M6 17v4m-2-2h4m5-16l2.286 6.857L21 12l-5.714 2.143L13 21l-2.286-6.857L5 12l5.714-2.143L13 3z"></path></svg> },
    { id: 'manga', label: 'Manga', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z"></path></svg> },
    { id: '3d-render', label: '3D Render', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M20 7l-8-4-8 4m16 0l-8 4m8-4v10l-8 4m0-10L4 7m8 4v10M4 7v10l8 4"></path></svg> },
    { id: 'illustration', label: 'Illustration', icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01"></path></svg> },
  ];

  const handleRatioChange = (ratio: AspectRatio) => {
    setCurrentRatio(ratio);
    onRegenerate(currentStyle, ratio);
  };

  const handleStyleChange = (style: GenerationStyle) => {
    setCurrentStyle(style);
    onRegenerate(style, currentRatio);
  };

  const exportAllAssets = async () => {
    if (assets.length === 0) return;
    setExporting(true);

    try {
      const zip = new JSZip();
      const folder = zip.folder(campaign.title.replace(/\s+/g, '_') || 'campaign_assets');

      const promises = assets.map(async (asset, index) => {
        let fileName = `${campaign.title}_${asset.style}_${asset.aspectRatio.replace(':', '-')}_${asset.language}_${index}`;

        if (asset.type === 'video' && asset.videoUrl) {
           const response = await fetch(asset.videoUrl);
           const blob = await response.blob();
           folder?.file(`${fileName}.mp4`, blob);
        } else if (asset.imageUrl) {
           // Handle base64
           const base64Data = asset.imageUrl.split(',')[1];
           folder?.file(`${fileName}.png`, base64Data, {base64: true});
        }
      });

      await Promise.all(promises);

      const content = await zip.generateAsync({type: "blob"});
      const url = window.URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = `afribrand_${campaign.title.replace(/\s+/g, '_')}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (e) {
      console.error("Failed to zip assets", e);
      alert("Could not export assets.");
    } finally {
      setExporting(false);
    }
  };

  const selectedPlatformData = platforms.find(p => p.id === platform);

  const getOverlayForPlatform = (asset: Asset) => {
    switch(platform) {
      case 'tiktok':
        return (
          <div className="absolute inset-0 flex flex-col justify-end p-4 pointer-events-none">
             <div className="absolute right-2 bottom-12 flex flex-col gap-4 items-center">
                <div className="w-8 h-8 rounded-full bg-slate-200 border border-white/50"></div>
                <div className="flex flex-col items-center">
                    <svg className="w-6 h-6 text-white drop-shadow-md" fill="currentColor" viewBox="0 0 24 24"><path d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"></path></svg>
                    <span className="text-[10px] text-white font-bold">8.2k</span>
                </div>
                <div className="flex flex-col items-center">
                    <svg className="w-6 h-6 text-white drop-shadow-md" fill="currentColor" viewBox="0 0 24 24"><path fillRule="evenodd" d="M18 10c0 3.866-3.582 7-8 7a8.841 8.841 0 01-4.083-.98L2 17l1.338-3.123C2.493 12.767 2 11.434 2 10c0-3.866 3.582-7 8-7s8 3.134 8 7zM7 9H5v2h2V9zm8 0h-2v2h2V9zM9 9h2v2H9V9z" clipRule="evenodd"></path></svg>
                    <span className="text-[10px] text-white font-bold">142</span>
                </div>
                <div className="flex flex-col items-center">
                    <svg className="w-6 h-6 text-white drop-shadow-md" fill="currentColor" viewBox="0 0 24 24"><path fillRule="evenodd" d="M3 17a1 1 0 011-1h12.586l-2.293-2.293a1 1 0 011.414-1.414l4 4a1 1 0 010 1.414l-4 4a1 1 0 01-1.414-1.414L16.586 18H4a1 1 0 01-1-1z" clipRule="evenodd"></path></svg>
                    <span className="text-[10px] text-white font-bold">Share</span>
                </div>
             </div>
             <div className="pr-12 text-white text-left drop-shadow-md">
                <p className="font-bold text-sm">@{dna.name.replace(/\s/g, '').toLowerCase()}</p>
                <p className="text-xs line-clamp-2 mt-1">{asset.caption}</p>
                <p className="text-[10px] mt-2 opacity-80">♫ Original Sound - {dna.name}</p>
             </div>
          </div>
        );
      case 'instagram':
        if(asset.aspectRatio === '9:16') { // Story Mode
             return (
                <div className="absolute inset-0 flex flex-col justify-between p-4 pointer-events-none">
                    <div className="flex items-center gap-2 mt-2">
                        <div className="w-6 h-6 rounded-full bg-slate-200 border border-white"></div>
                        <span className="text-white text-xs font-bold drop-shadow-md">{dna.name}</span>
                        <span className="text-white/60 text-xs">2h</span>
                    </div>
                    <div className="mb-8">
                        <div className="bg-white/90 text-slate-900 text-xs font-bold px-4 py-2 rounded-xl inline-block max-w-[80%] shadow-lg">
                           Link in bio! 👆
                        </div>
                    </div>
                </div>
             )
        }
        return ( // Feed Mode
            <div className="absolute inset-x-0 bottom-0 p-3 pointer-events-none bg-gradient-to-t from-black/50 to-transparent">
                 <div className="flex justify-between items-center text-white mb-2">
                    <div className="flex gap-3">
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z"></path></svg>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"></path></svg>
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 19l9 2-9-18-9 18 9-2zm0 0v-8"></path></svg>
                    </div>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M5 5a2 2 0 012-2h10a2 2 0 012 2v16l-7-3.5L5 21V5z"></path></svg>
                 </div>
            </div>
        );
      case 'linkedin':
        return (
            <div className="absolute bottom-4 left-4 right-4 bg-white/95 p-3 rounded-lg shadow-sm border border-slate-200 pointer-events-none">
                <p className="text-[10px] font-bold text-slate-800 uppercase tracking-wider mb-1">Promoted</p>
                <h5 className="text-xs font-bold text-slate-900 truncate">{asset.headline}</h5>
                <button className="mt-2 text-[10px] font-bold border border-slate-900 text-slate-900 px-3 py-1 rounded-full w-fit">Learn more</button>
            </div>
        );
      default:
        return (
            <div className="absolute inset-x-0 bottom-0 p-6 pointer-events-none bg-gradient-to-t from-black/60 to-transparent">
                <div className="flex items-center gap-3 mb-2">
                    <div className="w-8 h-8 rounded-full bg-slate-200 border border-white"></div>
                    <span className="text-white text-xs font-bold drop-shadow-md">{dna.name}</span>
                </div>
                <p className="text-white text-[10px] font-medium line-clamp-2 drop-shadow-md">{asset.caption}</p>
            </div>
        );
    }
  }

  return (
    <div className="space-y-12 py-12 animate-in zoom-in duration-500">
      <div className="flex flex-col lg:flex-row items-start justify-between gap-10">
        <div className="space-y-4 max-w-2xl">
          <div className="flex items-center gap-2">
            <span className="w-10 h-[2px] bg-amber-600"></span>
            <span className="text-[10px] font-black text-amber-600 uppercase tracking-[0.3em]">{t.assets.hub}</span>
          </div>
          <h2 className="text-5xl font-black text-slate-900 tracking-tight leading-none">{campaign.title}</h2>
          <p className="text-slate-500 font-medium text-lg leading-relaxed">{campaign.concept}</p>
        </div>

        <div className="flex flex-col gap-6 w-full lg:w-auto">
          {/* Platform Tabs */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-slate-100 flex gap-1 overflow-x-auto">
            {platforms.map((p) => (
              <button
                key={p.id}
                onClick={() => {
                  setPlatform(p.id);
                  if (!p.ratios.includes(currentRatio)) {
                    handleRatioChange(p.ratios[0]);
                  }
                }}
                className={`p-3 rounded-xl transition-all flex flex-col items-center justify-center min-w-[70px] flex-1 ${
                  platform === p.id ? 'bg-amber-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-400'
                }`}
              >
                <div className="mb-1">{p.icon}</div>
                <span className="text-[9px] font-black uppercase tracking-tighter whitespace-nowrap">{p.label}</span>
              </button>
            ))}
          </div>

          {/* Video Generation Controls */}
          <div className="bg-white p-4 rounded-2xl border border-slate-100 flex flex-col sm:flex-row items-center justify-between gap-4">
               <div className="flex flex-col gap-2">
                  <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">{t.assets.videoMode}</span>
                  <div className="flex gap-2">
                    <button 
                      onClick={() => setVideoMode('fast')}
                      className={`px-4 py-2 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'fast' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                    >
                      ⚡ Fast
                    </button>
                    <button 
                      onClick={() => setVideoMode('high-quality')}
                      className={`px-4 py-2 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'high-quality' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                    >
                      ✨ High Quality
                    </button>
                  </div>
               </div>
               <button 
                onClick={() => onGenerateVideo(currentRatio, videoMode)}
                className="w-full sm:w-auto px-6 py-4 bg-amber-600 text-white rounded-xl font-black shadow-lg shadow-amber-600/20 hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-2"
               >
                 <span className="text-lg">
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>
                 </span>
                 <span className="text-xs">{t.assets.generateVideo}</span>
               </button>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Style & Ratio Selection Sidebar */}
        <div className="lg:col-span-1 space-y-8">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.visualStyle}
                </h4>
                <div className="grid grid-cols-2 gap-3">
                  {styles.map((s) => (
                    <button
                      key={s.id}
                      onClick={() => handleStyleChange(s.id)}
                      className={`flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${
                        currentStyle === s.id 
                        ? 'bg-amber-50 border-amber-500 ring-1 ring-amber-500 shadow-sm' 
                        : 'bg-slate-50 border-slate-100 hover:border-amber-200'
                      }`}
                    >
                      <div className="text-slate-600">{s.icon}</div>
                      <span className="text-[10px] font-bold text-slate-600 text-center leading-tight">{s.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.formatRatio}
                </h4>
                <div className="flex flex-col gap-2">
                  {selectedPlatformData?.ratios.map((ratio) => (
                    <button
                      key={ratio}
                      onClick={() => handleRatioChange(ratio)}
                      className={`w-full py-3 px-4 rounded-xl text-xs font-black uppercase tracking-widest flex justify-between items-center transition-all ${
                        currentRatio === ratio 
                        ? 'bg-slate-900 text-white shadow-lg' 
                        : 'bg-slate-50 text-slate-500 border border-slate-100 hover:bg-white'
                      }`}
                    >
                      <span>{ratio}</span>
                      <span className="opacity-40">{ratio === '1:1' ? 'Square' : ratio === '9:16' ? 'Vertical' : ratio === '16:9' ? 'Wide' : 'Portrait'}</span>
                    </button>
                  ))}
                </div>
              </div>
           </div>

           <button 
              onClick={exportAllAssets}
              disabled={exporting || assets.length === 0}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm shadow-xl flex items-center justify-center gap-2 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
           >
              {exporting ? (
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
              )}
              {t.assets.exportZip}
           </button>
        </div>

        {/* Assets Main Display */}
        <div className="lg:col-span-3">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            {assets.map((asset) => (
              <div key={asset.id} className="group flex flex-col space-y-6">
                <div 
                    className={`relative rounded-[2rem] overflow-hidden shadow-2xl border-4 border-white bg-slate-100 ring-1 ring-slate-100 transition-all duration-500 mx-auto w-full`} 
                    style={{ aspectRatio: asset.aspectRatio.replace(':', '/') }}
                >
                  {asset.type === 'video' ? (
                    <video src={asset.videoUrl} className="w-full h-full object-cover" controls autoPlay loop muted />
                  ) : (
                    <img src={asset.imageUrl} alt="Asset" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 ease-out" />
                  )}

                  {/* Dynamic Platform Overlay */}
                  {getOverlayForPlatform(asset)}

                  {/* Language Badge */}
                  <div className="absolute top-4 right-4 bg-white/90 text-slate-900 px-3 py-1 rounded-full text-xs font-bold shadow-md z-20">
                     {asset.language}
                  </div>

                  {/* Hover Actions */}
                  <div className="absolute inset-0 bg-slate-900/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-8 backdrop-blur-md z-10">
                    <div className="text-center space-y-5 w-full">
                        <p className="text-white text-xs font-black uppercase tracking-widest">{asset.style} Style • {asset.aspectRatio}</p>
                        <p className="text-white/60 text-[10px]">{t.assets.optimizedFor} {platform}</p>
                        <div className="space-y-3">
                            <button 
                                onClick={() => onEdit(asset)}
                                className="w-full px-6 py-4 bg-white text-slate-900 rounded-2xl font-black shadow-xl hover:scale-105 transition-transform"
                            >
                                {t.assets.refine}
                            </button>
                        </div>
                    </div>
                  </div>
                </div>

                <div className="bg-white p-8 rounded-[2.5rem] shadow-xl border border-slate-100 relative group-hover:shadow-amber-100 transition-all">
                  <div className="absolute -top-4 left-8 flex gap-2">
                    <span className="px-4 py-1.5 bg-amber-600 text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg">
                      {asset.type}
                    </span>
                    <span className="px-4 py-1.5 bg-slate-900 text-white rounded-full text-[9px] font-black uppercase tracking-widest shadow-lg">
                      {asset.style}
                    </span>
                  </div>

                  <h4 className="text-xl font-black text-slate-900 mb-3 truncate mt-2">{asset.headline}</h4>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed line-clamp-3 font-medium">{asset.caption}</p>

                  <div className="flex items-center justify-between border-t border-slate-50 pt-5">
                    <div className="flex items-center gap-2">
                      <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Ready to Publish</span>
                    </div>
                    <button 
                        className="p-3 bg-slate-50 hover:bg-amber-50 text-slate-400 hover:text-amber-600 rounded-xl transition-all"
                        onClick={() => navigator.clipboard.writeText(asset.caption)}
                        title="Copy Caption"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3"></path></svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}

            <div 
              onClick={() => onRegenerate(currentStyle, currentRatio)}
              className="flex flex-col items-center justify-center border-2 border-dashed border-slate-200 rounded-[3.5rem] p-12 hover:bg-white/60 hover:border-amber-400 transition-all cursor-pointer group bg-slate-50/50 min-h-[400px]"
            >
                <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center text-slate-300 mb-6 group-hover:scale-110 group-hover:text-amber-500 group-hover:shadow-xl transition-all shadow-sm">
                    <svg className="w-10 h-10" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 6v6m0 0v6m0-6h6m-6 0H6"></path></svg>
                </div>
                <div className="text-center">
                    <p className="text-lg font-black text-slate-400 group-hover:text-amber-600 transition-colors uppercase tracking-widest">{t.assets.newVariant}</p>
                    <p className="text-xs text-slate-400 mt-2 font-medium">{t.assets.addFrame}</p>
                </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssetGenerator;

import React from 'react';
import { Campaign } from '../types';

interface CampaignPlannerProps {
  campaigns: Campaign[];
  onSelect: (campaign: Campaign) => void;
  t: any;
}

const CampaignPlanner: React.FC<CampaignPlannerProps> = ({ campaigns, onSelect, t }) => {
  const exportToCSV = (e: React.MouseEvent) => {
    e.stopPropagation();
    const headers = ["Campaign Title", "Concept", "Cultural Hook", "Suggested Platforms"];
    const rows = campaigns.map(c => [
      `"${c.title.replace(/"/g, '""')}"`,
      `"${c.concept.replace(/"/g, '""')}"`,
      `"${c.culturalHook.replace(/"/g, '""')}"`,
      `"${c.suggestedPlatforms.join(", ")}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(r => r.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "afribrand_campaign_ideas.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const shareCampaign = async (e: React.MouseEvent, campaign: Campaign) => {
    e.stopPropagation();
    const shareData = {
      title: campaign.title,
      text: `Check out this campaign idea: ${campaign.title} - ${campaign.concept}`,
      url: window.location.href // Ideally this would be a specific campaign link
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      alert("Sharing not supported on this browser.");
    }
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="text-left">
          <h2 className="text-3xl font-bold text-slate-900">{t.planner.title}</h2>
          <p className="text-slate-500">{t.planner.subtitle}</p>
