    // Basic mapping of countries to regions/timezones
    const westAfrica = ['Senegal', 'Ghana', 'Nigeria', 'Côte d\'Ivoire', 'Benin', 'Togo', 'Burkina Faso', 'Mali'];
    const eastAfrica = ['Kenya', 'Tanzania', 'Uganda', 'Ethiopia', 'Rwanda'];
    const northAfrica = ['Morocco', 'Egypt', 'Tunisia', 'Algeria'];
    const southernAfrica = ['South Africa', 'Namibia', 'Botswana', 'Zimbabwe'];

    if (westAfrica.includes(country)) {
      return { region: 'West Africa', bestTimes: ['07:30 GMT', '18:15 GMT', '20:00 GMT'], bestDays: ['Tue', 'Thu', 'Sat'] };
