  };

  const handleStyleChange = (style: GenerationStyle) => {
    setCurrentStyle(style);
    onRegenerate(style, currentRatio, selectedProduct || undefined);
  };

  const exportAllAssets = async () => {
    if (assets.length === 0) return;
    setExporting(true);

    try {
      const zip = new JSZip();
      const folder = zip.folder(campaign.title.replace(/\s+/g, '_') || 'campaign_assets');

      const promises = assets.map(async (asset, index) => {
        let fileName = `${campaign.title}_${asset.style}_${asset.aspectRatio.replace(':', '-')}_${asset.language}_${index}`;

        if (asset.type === 'video' && asset.videoUrl) {
           const response = await fetch(asset.videoUrl);
           const blob = await response.blob();
           folder?.file(`${fileName}.mp4`, blob);
        } else if (asset.imageUrl) {
           const base64Data = asset.imageUrl.split(',')[1];
           folder?.file(`${fileName}.png`, base64Data, {base64: true});
        }
      });

      await Promise.all(promises);

      const content = await zip.generateAsync({type: "blob"});
      const url = window.URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = `afribrand_${campaign.title.replace(/\s+/g, '_')}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (e) {
      console.error("Failed to zip assets", e);
      alert("Could not export assets.");
    } finally {
      setExporting(false);
    }
  };

  const selectedPlatformData = platforms.find(p => p.id === platform);

  const getOverlayForPlatform = (asset: Asset) => {
     // Simplified overlay logic from previous example
     if (platform === 'tiktok') {
        return <div className="absolute inset-0 flex flex-col justify-end p-4 pointer-events-none text-white font-bold text-xs"><p>@{dna.name}</p></div>
     }
     return <div className="absolute inset-x-0 bottom-0 p-4 pointer-events-none bg-black/40 text-white text-xs"><p>@{dna.name}</p></div>
  };

  return (
    <div className="space-y-12 py-12 animate-in zoom-in duration-500">
      <div className="flex flex-col lg:flex-row items-start justify-between gap-10">
        <div className="space-y-4 max-w-2xl">
          <div className="flex items-center gap-2">
            <span className="w-10 h-[2px] bg-amber-600"></span>
            <span className="text-[10px] font-black text-amber-600 uppercase tracking-[0.3em]">{t.assets.hub}</span>
          </div>
          <h2 className="text-5xl font-black text-slate-900 tracking-tight leading-none">{campaign.title}</h2>
          <p className="text-slate-500 font-medium text-lg leading-relaxed">{campaign.concept}</p>
        </div>

        <div className="flex flex-col gap-6 w-full lg:w-auto">
          {/* Platform Tabs */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-slate-100 flex gap-1 overflow-x-auto">
            {platforms.map((p) => (
              <button
                key={p.id}
                onClick={() => {
                  setPlatform(p.id);
                  if (!p.ratios.includes(currentRatio)) {
                    handleRatioChange(p.ratios[0]);
                  }
                }}
                className={`p-3 rounded-xl transition-all flex flex-col items-center justify-center min-w-[70px] flex-1 ${
                  platform === p.id ? 'bg-amber-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-400'
                }`}
              >
                <div className="mb-1">{p.icon}</div>
                <span className="text-[9px] font-black uppercase tracking-tighter whitespace-nowrap">{p.label}</span>
              </button>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
              {/* Catalog Selection */}
              <div className="relative">
                <button 
                    onClick={() => setShowCatalog(!showCatalog)}
                    className="w-full sm:w-auto px-4 py-4 bg-white text-slate-900 border border-slate-200 rounded-xl font-bold flex items-center justify-between gap-3 shadow-sm hover:border-amber-400 transition-all"
                >
                    <div className="flex items-center gap-2">
                        <svg className="w-5 h-5 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                        <span className="text-xs">{selectedProduct ? selectedProduct.name : t.assets.connectCatalog}</span>
                    </div>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                </button>
                {showCatalog && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-xl border border-slate-100 p-2 z-50 w-64">
                        <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-3 py-2">{t.assets.selectProduct}</div>
                        {catalog.map(prod => (
                            <button
                                key={prod.id}
                                onClick={() => {
                                    setSelectedProduct(prod);
                                    setShowCatalog(false);
                                    onRegenerate(currentStyle, currentRatio, prod);
                                }}
                                className="w-full text-left px-3 py-2 hover:bg-slate-50 rounded-lg flex items-center gap-3"
                            >
                                <img src={prod.imageUrl} className="w-8 h-8 rounded-lg object-cover" alt="" />
                                <div>
                                    <p className="text-xs font-bold text-slate-900">{prod.name}</p>
                                    <p className="text-[10px] text-slate-500">{prod.price}</p>
                                </div>
                            </button>
                        ))}
                        <button 
                            onClick={() => { setSelectedProduct(null); setShowCatalog(false); }}
                            className="w-full text-left px-3 py-2 hover:bg-red-50 text-red-600 rounded-lg text-xs font-bold mt-2"
                        >
                            {t.assets.noProduct}
                        </button>
                    </div>
                )}
              </div>

             {/* Video Controls */}
              <div className="flex-1 bg-white px-4 py-2 rounded-2xl border border-slate-100 flex items-center justify-between gap-4">
                   <div className="flex gap-2">
                        <button 
                          onClick={() => setVideoMode('fast')}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'fast' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                        >
                          Fast
                        </button>
                        <button 
                          onClick={() => setVideoMode('high-quality')}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'high-quality' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                        >
                          High
                        </button>
                   </div>
                   <button 
                    onClick={() => onGenerateVideo(currentRatio, videoMode)}
                    className="p-3 bg-amber-600 text-white rounded-xl shadow-lg shadow-amber-600/20 hover:scale-105 active:scale-95 transition-all"
                   >
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>
                   </button>
              </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Style & Ratio Selection Sidebar */}
        <div className="lg:col-span-1 space-y-8">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.visualStyle}
