            <div className="mt-8 flex items-center text-amber-600 font-bold text-sm">
                {t.planner.generate} <span className="ml-2 group-hover:translate-x-1 transition-transform">→</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

