};

export default BrandSettings;

import React, { useState } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset, GenerationStyle, AspectRatio, SocialAccount, SocialPlatform, Product } from './types';
import * as aiService from './geminiService';
import { socialService } from './socialService';
import Landing from './components/Landing';
import Auth from './components/Auth';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';
import BrandSettings from './components/BrandSettings';
import { translations, Language } from './i18n';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('landing');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [lang, setLang] = useState<Language>('fr');

  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Middle-class urban professionals',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA',
    defaultStyle: 'natural'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [socialAccounts, setSocialAccounts] = useState<SocialAccount[]>([
    { platform: 'instagram', connected: false },
    { platform: 'facebook', connected: false },
    { platform: 'whatsapp', connected: false }
  ]);

  const t = translations[lang];

  const handleConnectAccount = async (platform: SocialPlatform) => {
    setLoading(true);
    setLoadingMessage(`Connecting to ${platform}...`);
    try {
        const success = await socialService.connectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: true } : acc));
        }
    } catch (e) {
        console.error(e);
        alert("Failed to connect account.");
    } finally {
        setLoading(false);
    }
  };

  const handleDisconnectAccount = async (platform: SocialPlatform) => {
    try {
        const success = await socialService.disconnectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: false } : acc));
        }
    } catch (e) {
        console.error(e);
    }
  };

  const handlePostAsset = async (platform: SocialPlatform, assetId: string) => {
    const asset = assets.find(a => a.id === assetId);
    if (!asset) return;

    setLoading(true);
    setLoadingMessage(`Posting to ${platform}...`);
    try {
        const success = await socialService.postAsset(platform, assetId, asset);
        if (success) {
             setAssets(prev => prev.map(a => a.id === assetId ? { ...a, postedTo: [...(a.postedTo || []), platform] } : a));
             alert(`Successfully posted to ${platform}!`);
        }
    } catch (e) {
        console.error(e);
        alert("Failed to post asset.");
    } finally {
        setLoading(false);
    }
  };

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage(t.loading.strategy);
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);

      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);

      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen gradient-bg text-slate-900 selection:bg-amber-200 flex flex-col">
      {step !== 'landing' && step !== 'auth' && (
        <header className="px-6 py-4 glass sticky top-0 z-50 flex justify-between items-center shadow-lg border-b border-white/20">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-amber-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tight leading-none">AfriBrand <span className="text-amber-600">AI</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{t.tagline}</p>
            </div>
          </div>
          <div className="flex gap-4 items-center">
             <div className="flex bg-white/50 rounded-lg p-1 border border-slate-200">
                <button 
                  onClick={() => setLang('en')} 
                  className={`px-2 py-1 text-xs font-bold rounded-md transition-all ${lang === 'en' ? 'bg-amber-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  EN
                </button>
                <button 
                  onClick={() => setLang('fr')} 
                  className={`px-2 py-1 text-xs font-bold rounded-md transition-all ${lang === 'fr' ? 'bg-amber-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  FR
                </button>
             </div>

              {step === 'assets' && (
                  <button 
                      onClick={() => setStep('calendar')}
                      className="px-4 py-2 bg-white/50 hover:bg-white text-slate-700 rounded-xl text-xs font-bold border border-slate-200 transition-all flex items-center gap-2"
                  >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                      {t.calendar}
                  </button>
              )}

              {step !== 'welcome' && (
                <>
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2 rounded-xl transition-all ${step === 'settings' ? 'bg-slate-900 text-white' : 'bg-white text-slate-500 hover:text-amber-600'}`}
                      title="Settings & Team"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                    <button 
                        onClick={() => setStep('welcome')}
                        className="px-4 py-2 bg-amber-600 text-white rounded-xl text-xs font-bold shadow-lg shadow-amber-600/20 hover:bg-amber-700 transition-all"
                    >
                        {t.reset}
                    </button>
                </>
              )}
          </div>
        </header>
      )}

      <main className={`flex-1 ${step === 'landing' || step === 'auth' ? '' : 'max-w-6xl mx-auto w-full p-6'}`}>
        {loading && (
          <div className="fixed inset-0 bg-white/80 backdrop-blur-xl z-[100] flex flex-col items-center justify-center text-center p-8">
            <div className="relative">
                <div className="w-24 h-24 border-4 border-amber-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center font-bold text-amber-600">A</div>
            </div>
            <h3 className="text-3xl font-black text-slate-800 mt-8 mb-2">{loadingMessage}</h3>
            <p className="text-slate-500 max-w-sm">{t.loading.generic}</p>
          </div>
        )}

        {step === 'landing' && <Landing onStart={() => setStep('auth')} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={handleConnectAccount} onDisconnectAccount={handleDisconnectAccount} onBack={() => setStep('welcome')} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={handleConnectAccount}
            onPostAsset={handlePostAsset}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      <footer className="p-8 bg-slate-900 text-slate-400 text-center border-t border-slate-800">
        <div className="max-w-6xl mx-auto space-y-4">
          <div className="flex justify-center gap-8 mb-4">
            <a href="#" className="hover:text-white transition-colors">Vision</a>
            <a href="#" className="hover:text-white transition-colors">Pricing</a>
            <a href="#" className="hover:text-white transition-colors">Terms</a>
            <a href="#" className="hover:text-white transition-colors">Privacy</a>
          </div>
          <p className="text-xs uppercase tracking-[0.2em] font-bold">
            &copy; 2025 AfriBrand AI • Owned by Malthus AMETEPE
          </p>
          <p className="text-[10px] opacity-50 max-w-lg mx-auto leading-relaxed">
            High-end marketing automation for African SMEs. Powered by Gemini Cultural Intelligence. Optimized for low-bandwidth environments. Built with precision for the future of local commerce.
          </p>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { Campaign } from '../types';
import { socialService } from '../socialService';

interface CampaignPlannerProps {
  campaigns: Campaign[];
  onSelect: (campaign: Campaign) => void;
  t: any;
  country?: string;
}

const CampaignPlanner: React.FC<CampaignPlannerProps> = ({ campaigns, onSelect, t, country }) => {
  const scheduleRecommendation = socialService.getRegionSchedule(country || 'Senegal');

  const exportToCSV = (e: React.MouseEvent) => {
    e.stopPropagation();
    const headers = ["Campaign Title", "Concept", "Cultural Hook", "Suggested Platforms"];
    const rows = campaigns.map(c => [
      `"${c.title.replace(/"/g, '""')}"`,
      `"${c.concept.replace(/"/g, '""')}"`,
      `"${c.culturalHook.replace(/"/g, '""')}"`,
      `"${c.suggestedPlatforms.join(", ")}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(r => r.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "afribrand_campaign_ideas.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const shareCampaign = async (e: React.MouseEvent, campaign: Campaign) => {
    e.stopPropagation();
    const shareData = {
      title: campaign.title,
      text: `Check out this campaign idea: ${campaign.title} - ${campaign.concept}`,
      url: window.location.href
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      alert("Sharing not supported on this browser.");
    }
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="text-left">
          <h2 className="text-3xl font-bold text-slate-900">{t.planner.title}</h2>
          <p className="text-slate-500">{t.planner.subtitle}</p>
        </div>
        <button 
          onClick={exportToCSV}
          className="px-6 py-3 bg-slate-900 text-white rounded-2xl font-bold text-sm shadow-xl flex items-center gap-2 hover:bg-slate-800 transition-all"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
          {t.planner.export}
        </button>
      </div>

      {/* Smart Schedule Recommendation Banner */}
      <div className="bg-gradient-to-r from-amber-50 to-orange-50 border border-amber-100 rounded-3xl p-6 flex flex-col md:flex-row items-center justify-between gap-6 shadow-sm">
         <div className="flex items-center gap-4">
             <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-md text-amber-500">
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"></path></svg>
             </div>
             <div>
                 <h4 className="font-bold text-slate-900">{t.planner.smartSchedule}</h4>
                 <p className="text-sm text-slate-500">{t.planner.optimalTime} <span className="font-bold text-slate-800">{scheduleRecommendation.region}</span></p>
             </div>
         </div>
         <div className="flex flex-wrap gap-2">
            {scheduleRecommendation.bestTimes.map(time => (
                <span key={time} className="px-4 py-2 bg-white rounded-xl text-xs font-bold text-slate-700 shadow-sm border border-slate-100">{time}</span>
            ))}
            {scheduleRecommendation.bestDays.map(day => (
                <span key={day} className="px-4 py-2 bg-amber-100 rounded-xl text-xs font-bold text-amber-800 shadow-sm border border-amber-200">{day}</span>
            ))}
         </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {campaigns.map((camp) => (
          <div 
            key={camp.id}
            className="group relative bg-white p-8 rounded-3xl shadow-sm border border-slate-100 hover:shadow-xl hover:-translate-y-1 transition-all cursor-pointer overflow-hidden"
            onClick={() => onSelect(camp)}
          >
            <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
               <svg className="w-16 h-16" fill="currentColor" viewBox="0 0 24 24"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z"/></svg>
            </div>

            <button 
              onClick={(e) => shareCampaign(e, camp)}
              className="absolute top-4 right-4 p-2 bg-slate-50 hover:bg-amber-100 rounded-full transition-colors z-10 text-slate-400 hover:text-amber-600"
              title={t.planner.share}
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z"></path></svg>
            </button>

            <div className="mb-4">
                <span className="px-3 py-1 bg-amber-100 text-amber-700 text-xs font-bold rounded-full uppercase tracking-tighter">Idea #{camp.id}</span>
            </div>
            <h3 className="text-xl font-bold text-slate-900 mb-3">{camp.title}</h3>
            <p className="text-sm text-slate-600 mb-6 leading-relaxed line-clamp-3">{camp.concept}</p>

            <div className="bg-slate-50 p-3 rounded-xl mb-6">
                <p className="text-xs font-bold text-slate-400 uppercase mb-1">{t.planner.hook}</p>
                <p className="text-xs text-slate-700 font-medium">{camp.culturalHook}</p>
            </div>

            <div className="flex gap-2 flex-wrap">
              {camp.suggestedPlatforms.map((p, i) => (
                <span key={i} className="text-[10px] font-bold text-slate-400 border border-slate-200 px-2 py-0.5 rounded-md uppercase tracking-wider">{p}</span>
              ))}
            </div>

            <div className="mt-8 flex items-center text-amber-600 font-bold text-sm">
                {t.planner.generate} <span className="ml-2 group-hover:translate-x-1 transition-transform">→</span>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CampaignPlanner;

import React, { useState } from 'react';
import { Asset, Campaign, PreviewPlatform, GenerationStyle, BrandDNA, AspectRatio, VideoQualityMode, Product, SocialAccount, SocialPlatform } from '../types';
import JSZip from 'jszip';
import { socialService } from '../socialService';

interface AssetGeneratorProps {
  assets: Asset[];
  campaign: Campaign;
  dna: BrandDNA;
  onEdit: (asset: Asset) => void;
  onGenerateVideo: (ratio: AspectRatio, mode: VideoQualityMode) => void;
  onRegenerate: (style: GenerationStyle, ratio: AspectRatio, product?: Product) => void;
  t: any;
  socialAccounts: SocialAccount[];
  onConnectAccount: (platform: SocialPlatform) => void;
  onPostAsset: (platform: SocialPlatform, assetId: string) => void;
}

const AssetGenerator: React.FC<AssetGeneratorProps> = ({ 
  assets, campaign, dna, onEdit, onGenerateVideo, onRegenerate, t, socialAccounts, onConnectAccount, onPostAsset 
}) => {
  const [platform, setPlatform] = useState<PreviewPlatform>('instagram');
  const [currentStyle, setCurrentStyle] = useState<GenerationStyle>('natural');
