  const [showCatalog, setShowCatalog] = useState(false);

  // Mock Catalog Data
  const catalog = socialService.getMockCatalog();

  const platforms: { id: PreviewPlatform; icon: React.ReactNode; label: string; ratios: AspectRatio[] }[] = [
