              </div>

              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.formatRatio}
                </h4>
                <div className="flex flex-col gap-2">
                  {selectedPlatformData?.ratios.map((ratio) => (
                    <button
                      key={ratio}
                      onClick={() => handleRatioChange(ratio)}
                      className={`w-full py-3 px-4 rounded-xl text-xs font-black uppercase tracking-widest flex justify-between items-center transition-all ${
                        currentRatio === ratio 
                        ? 'bg-slate-900 text-white shadow-lg' 
                        : 'bg-slate-50 text-slate-500 border border-slate-100 hover:bg-white'
                      }`}
                    >
                      <span>{ratio}</span>
                      <span className="opacity-40">{ratio === '1:1' ? 'Square' : ratio === '9:16' ? 'Vertical' : ratio === '16:9' ? 'Wide' : 'Portrait'}</span>
                    </button>
                  ))}
                </div>
              </div>
           </div>

           <button 
              onClick={exportAllAssets}
              disabled={exporting || assets.length === 0}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm shadow-xl flex items-center justify-center gap-2 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
           >
              {exporting ? (
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
              )}
              {t.assets.exportZip}
           </button>
        </div>

        {/* Assets Main Display */}
        <div className="lg:col-span-3">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            {assets.map((asset) => (
              <div key={asset.id} className="group flex flex-col space-y-6">
                <div 
                    className={`relative rounded-[2rem] overflow-hidden shadow-2xl border-4 border-white bg-slate-100 ring-1 ring-slate-100 transition-all duration-500 mx-auto w-full`} 
                    style={{ aspectRatio: asset.aspectRatio.replace(':', '/') }}
                >
                  {asset.type === 'video' ? (
                    <video src={asset.videoUrl} className="w-full h-full object-cover" controls autoPlay loop muted />
                  ) : (
                    <img src={asset.imageUrl} alt="Asset" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 ease-out" />
                  )}

                  {getOverlayForPlatform(asset)}

                  <div className="absolute top-4 right-4 bg-white/90 text-slate-900 px-3 py-1 rounded-full text-xs font-bold shadow-md z-20">
                     {asset.language}
                  </div>

                  <div className="absolute inset-0 bg-slate-900/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-8 backdrop-blur-md z-10">
                    <div className="text-center space-y-5 w-full">
                        <p className="text-white text-xs font-black uppercase tracking-widest">{asset.style} Style • {asset.aspectRatio}</p>
                        <div className="space-y-3">
                            <button 
                                onClick={() => onEdit(asset)}
                                className="w-full px-6 py-4 bg-white text-slate-900 rounded-2xl font-black shadow-xl hover:scale-105 transition-transform"
                            >
                                {t.assets.refine}
                            </button>
                        </div>
                    </div>
                  </div>
                </div>

                <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-100 relative group-hover:shadow-amber-100 transition-all">
                  <h4 className="text-xl font-black text-slate-900 mb-3 truncate mt-2">{asset.headline}</h4>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed line-clamp-3 font-medium">{asset.caption}</p>

                  <div className="flex items-center justify-between border-t border-slate-50 pt-5 gap-3">
                     {/* Social Posting Buttons */}
                     {['instagram', 'facebook', 'whatsapp'].map(p => {
                         const account = socialAccounts.find(a => a.platform === p);
                         const isPosted = asset.postedTo?.includes(p as SocialPlatform);
                         return (
                            <button
                                key={p}
                                onClick={() => account?.connected && !isPosted ? onPostAsset(p as SocialPlatform, asset.id) : !account?.connected ? onConnectAccount(p as SocialPlatform) : null}
                                className={`p-2 rounded-full border transition-all ${isPosted ? 'bg-green-100 text-green-600 border-green-200' : account?.connected ? 'bg-white text-slate-400 hover:text-amber-600 border-slate-100' : 'bg-slate-50 text-slate-300 border-transparent'}`}
                                title={account?.connected ? (isPosted ? t.assets.social.posted : t.assets.social.post) : t.assets.social.connect}
                            >
                                {/* Icons for generic social platforms */}
                                {p === 'instagram' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>}
                                {p === 'facebook' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 2h-3a5 5 0 00-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 011-1h3z"></path></svg>}
                                {p === 'whatsapp' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z"></path></svg>}
                            </button>
                         );
                     })}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssetGenerator;

import React, { useState } from 'react';
import { Asset, Campaign, PreviewPlatform, GenerationStyle, BrandDNA, AspectRatio, VideoQualityMode, Product, SocialAccount, SocialPlatform } from '../types';
import JSZip from 'jszip';
import { socialService } from '../socialService';

interface AssetGeneratorProps {
  assets: Asset[];
  campaign: Campaign;
  dna: BrandDNA;
  onEdit: (asset: Asset) => void;
  onGenerateVideo: (ratio: AspectRatio, mode: VideoQualityMode) => void;
  onRegenerate: (style: GenerationStyle, ratio: AspectRatio, product?: Product) => void;
  t: any;
  socialAccounts: SocialAccount[];
  onConnectAccount: (platform: SocialPlatform) => void;
  onPostAsset: (platform: SocialPlatform, assetId: string) => void;
