}

export type AppStep = 'landing' | 'auth' | 'welcome' | 'analysis' | 'dna' | 'ideation' | 'assets' | 'editor' | 'calendar' | 'settings';

export interface UserInput {
  businessName: string;
  url: string;
  description: string;
  country: string;
  targetAudience: string;
