  bestDays: string[];
}

export type Role = 'Admin' | 'Editor' | 'Viewer';

export interface TeamMember {
  id: string;
  name: string;
  email: string;
  role: Role;
  avatar: string;
}

export interface ActivityLog {
  id: string;
  user: string;
