  const handleRatioChange = (ratio: AspectRatio) => {
    setCurrentRatio(ratio);
    onRegenerate(currentStyle, ratio, selectedProduct || undefined);
  };

  const handleStyleChange = (style: GenerationStyle) => {
    setCurrentStyle(style);
    onRegenerate(style, currentRatio, selectedProduct || undefined);
  };

  const exportAllAssets = async () => {
    if (assets.length === 0) return;
    setExporting(true);

    try {
      const zip = new JSZip();
      // Sanitize campaign title for folder name
      const safeFolderName = campaign.title.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'campaign_assets';
      const folder = zip.folder(safeFolderName);

      const promises = assets.map(async (asset, index) => {
        // Descriptive naming: campaign_title_style_ratio_language_index
        const safeTitle = campaign.title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
        const safeStyle = asset.style.toLowerCase();
        const safeRatio = asset.aspectRatio.replace(':', '-');

        let fileName = `${safeTitle}_${safeStyle}_${safeRatio}_${asset.language}_${index}`;

        if (asset.type === 'video' && asset.videoUrl) {
           const response = await fetch(asset.videoUrl);
           const blob = await response.blob();
           folder?.file(`${fileName}.mp4`, blob);
        } else if (asset.imageUrl) {
           // Handle base64 encoded images
           const parts = asset.imageUrl.split(',');
           if (parts.length === 2) {
               folder?.file(`${fileName}.png`, parts[1], {base64: true});
           }
        }
      });

      await Promise.all(promises);

      const content = await zip.generateAsync({type: "blob"});
      const url = window.URL.createObjectURL(content);
      const link = document.createElement('a');
      link.href = url;
      link.download = `afribrand_${safeFolderName}.zip`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
    } catch (e) {
      console.error("Failed to zip assets", e);
      alert("Could not export assets.");
    } finally {
      setExporting(false);
    }
  };

  const selectedPlatformData = platforms.find(p => p.id === platform);

  const getOverlayForPlatform = (asset: Asset) => {
     if (platform === 'tiktok') {
        return <div className="absolute inset-0 flex flex-col justify-end p-4 pointer-events-none text-white font-bold text-xs"><p>@{dna.name.replace(/\s/g, '').toLowerCase()}</p></div>
     }
     return <div className="absolute inset-x-0 bottom-0 p-4 pointer-events-none bg-black/40 text-white text-xs"><p>@{dna.name}</p></div>
  };

  const handlePostClick = async (platform: SocialPlatform, assetId: string) => {
      const key = `${assetId}-${platform}`;
      setPostingStates(prev => ({ ...prev, [key]: true }));
      try {
          await onPostAsset(platform, assetId);
      } finally {
          setPostingStates(prev => ({ ...prev, [key]: false }));
      }
  };

  return (
    <div className="space-y-12 py-12 animate-in zoom-in duration-500">
      <div className="flex flex-col lg:flex-row items-start justify-between gap-10">
        <div className="space-y-4 max-w-2xl">
          <div className="flex items-center gap-2">
            <span className="w-10 h-[2px] bg-amber-600"></span>
            <span className="text-[10px] font-black text-amber-600 uppercase tracking-[0.3em]">{t.assets.hub}</span>
          </div>
          <h2 className="text-5xl font-black text-slate-900 tracking-tight leading-none">{campaign.title}</h2>
          <p className="text-slate-500 font-medium text-lg leading-relaxed">{campaign.concept}</p>
        </div>

        <div className="flex flex-col gap-6 w-full lg:w-auto">
          {/* Platform Tabs */}
          <div className="bg-white p-2 rounded-2xl shadow-sm border border-slate-100 flex gap-1 overflow-x-auto">
            {platforms.map((p) => (
              <button
                key={p.id}
                onClick={() => {
                  setPlatform(p.id);
                  if (!p.ratios.includes(currentRatio)) {
                    handleRatioChange(p.ratios[0]);
                  }
                }}
                className={`p-3 rounded-xl transition-all flex flex-col items-center justify-center min-w-[70px] flex-1 ${
                  platform === p.id ? 'bg-amber-600 text-white shadow-lg' : 'hover:bg-slate-50 text-slate-400'
                }`}
              >
                <div className="mb-1">{p.icon}</div>
                <span className="text-[9px] font-black uppercase tracking-tighter whitespace-nowrap">{p.label}</span>
              </button>
            ))}
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
              {/* Catalog Selection */}
              <div className="relative">
                <button 
                    onClick={() => userRole !== 'Viewer' ? setShowCatalog(!showCatalog) : null}
                    disabled={userRole === 'Viewer'}
                    className={`w-full sm:w-auto px-4 py-4 bg-white text-slate-900 border border-slate-200 rounded-xl font-bold flex items-center justify-between gap-3 shadow-sm transition-all ${userRole !== 'Viewer' ? 'hover:border-amber-400' : 'opacity-50 cursor-not-allowed'}`}
                >
                    <div className="flex items-center gap-2">
                        <svg className="w-5 h-5 text-green-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                        <span className="text-xs">{selectedProduct ? selectedProduct.name : t.assets.connectCatalog}</span>
                    </div>
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7"></path></svg>
                </button>
                {showCatalog && (
                    <div className="absolute top-full left-0 right-0 mt-2 bg-white rounded-2xl shadow-xl border border-slate-100 p-2 z-50 w-64">
                        <div className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-3 py-2">{t.assets.selectProduct}</div>
                        {catalog.map(prod => (
                            <button
                                key={prod.id}
                                onClick={() => {
                                    setSelectedProduct(prod);
                                    setShowCatalog(false);
                                    onRegenerate(currentStyle, currentRatio, prod);
                                }}
                                className="w-full text-left px-3 py-2 hover:bg-slate-50 rounded-lg flex items-center gap-3"
                            >
                                <img src={prod.imageUrl} className="w-8 h-8 rounded-lg object-cover" alt="" />
                                <div>
                                    <p className="text-xs font-bold text-slate-900">{prod.name}</p>
                                    <p className="text-[10px] text-slate-500">{prod.price}</p>
                                </div>
                            </button>
                        ))}
                        <button 
                            onClick={() => { setSelectedProduct(null); setShowCatalog(false); }}
                            className="w-full text-left px-3 py-2 hover:bg-red-50 text-red-600 rounded-lg text-xs font-bold mt-2"
                        >
                            {t.assets.noProduct}
                        </button>
                    </div>
                )}
              </div>

             {/* Video Controls */}
              <div className="flex-1 bg-white px-4 py-2 rounded-2xl border border-slate-100 flex items-center justify-between gap-4">
                   <div className="flex gap-2">
                        <button 
                          onClick={() => setVideoMode('fast')}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'fast' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                        >
                          Fast
                        </button>
                        <button 
                          onClick={() => setVideoMode('high-quality')}
                          className={`px-3 py-1.5 rounded-lg text-[10px] font-bold border transition-all ${videoMode === 'high-quality' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-50 text-slate-500 border-slate-200'}`}
                        >
                          High
                        </button>
                   </div>
                   <button 
                    onClick={() => userRole !== 'Viewer' ? onGenerateVideo(currentRatio, videoMode) : null}
                    disabled={userRole === 'Viewer'}
                    className={`p-3 rounded-xl shadow-lg transition-all ${userRole !== 'Viewer' ? 'bg-amber-600 text-white shadow-amber-600/20 hover:scale-105 active:scale-95' : 'bg-slate-200 text-slate-400 cursor-not-allowed shadow-none'}`}
                   >
                     <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z"></path></svg>
                   </button>
              </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
        {/* Style & Ratio Selection Sidebar */}
        <div className="lg:col-span-1 space-y-8">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.visualStyle}
                </h4>
                <div className="grid grid-cols-2 gap-3">
                  {styles.map((s) => (
                    <button
                      key={s.id}
                      onClick={() => handleStyleChange(s.id)}
                      disabled={userRole === 'Viewer'}
                      className={`flex flex-col items-center gap-2 p-3 rounded-2xl border transition-all ${
                        currentStyle === s.id 
                        ? 'bg-amber-50 border-amber-500 ring-1 ring-amber-500 shadow-sm' 
                        : 'bg-slate-50 border-slate-100'
                      } ${userRole === 'Viewer' ? 'opacity-50 cursor-not-allowed' : 'hover:border-amber-200'}`}
                    >
                      <div className="text-slate-600">{s.icon}</div>
                      <span className="text-[10px] font-bold text-slate-600 text-center leading-tight">{s.label}</span>
                    </button>
                  ))}
                </div>
              </div>

              <div className="space-y-4">
                <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest flex items-center gap-2">
                   {t.assets.formatRatio}
                </h4>
                <div className="flex flex-col gap-2">
                  {selectedPlatformData?.ratios.map((ratio) => (
                    <button
                      key={ratio}
                      onClick={() => handleRatioChange(ratio)}
                      disabled={userRole === 'Viewer'}
                      className={`w-full py-3 px-4 rounded-xl text-xs font-black uppercase tracking-widest flex justify-between items-center transition-all ${
                        currentRatio === ratio 
                        ? 'bg-slate-900 text-white shadow-lg' 
                        : 'bg-slate-50 text-slate-500 border border-slate-100'
                      } ${userRole === 'Viewer' ? 'opacity-50 cursor-not-allowed' : 'hover:bg-white'}`}
                    >
                      <span>{ratio}</span>
                      <span className="opacity-40">{ratio === '1:1' ? 'Square' : ratio === '9:16' ? 'Vertical' : ratio === '16:9' ? 'Wide' : 'Portrait'}</span>
                    </button>
                  ))}
                </div>
              </div>
           </div>

           <button 
              onClick={exportAllAssets}
              disabled={exporting || assets.length === 0}
              className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black text-sm shadow-xl flex items-center justify-center gap-2 hover:scale-105 active:scale-95 transition-all disabled:opacity-50 disabled:scale-100"
           >
              {exporting ? (
                <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
              ) : (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
              )}
              {t.assets.exportZip}
           </button>
        </div>

        {/* Assets Main Display */}
        <div className="lg:col-span-3">
           <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
            {assets.map((asset) => (
              <div key={asset.id} className="group flex flex-col space-y-6">
                <div 
                    className={`relative rounded-[2rem] overflow-hidden shadow-2xl border-4 border-white bg-slate-100 ring-1 ring-slate-100 transition-all duration-500 mx-auto w-full`} 
                    style={{ aspectRatio: asset.aspectRatio.replace(':', '/') }}
                >
                  {asset.type === 'video' ? (
                    <video src={asset.videoUrl} className="w-full h-full object-cover" controls autoPlay loop muted />
                  ) : (
                    <img src={asset.imageUrl} alt="Asset" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000 ease-out" />
                  )}

                  {getOverlayForPlatform(asset)}

                  <div className="absolute top-4 right-4 bg-white/90 text-slate-900 px-3 py-1 rounded-full text-xs font-bold shadow-md z-20">
                     {asset.language}
                  </div>

                  {userRole !== 'Viewer' && (
                    <div className="absolute inset-0 bg-slate-900/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-8 backdrop-blur-md z-10">
                        <div className="text-center space-y-5 w-full">
                            <p className="text-white text-xs font-black uppercase tracking-widest">{asset.style} Style • {asset.aspectRatio}</p>
                            <div className="space-y-3">
                                <button 
                                    onClick={() => onEdit(asset)}
                                    className="w-full px-6 py-4 bg-white text-slate-900 rounded-2xl font-black shadow-xl hover:scale-105 transition-transform"
                                >
                                    {t.assets.refine}
                                </button>
                            </div>
                        </div>
                    </div>
                  )}
                </div>

                <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-100 relative group-hover:shadow-amber-100 transition-all">
                  <h4 className="text-xl font-black text-slate-900 mb-3 truncate mt-2">{asset.headline}</h4>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed line-clamp-3 font-medium">{asset.caption}</p>

                  <div className="flex items-center justify-between border-t border-slate-50 pt-5 gap-3">
                     {/* Social Posting Buttons */}
                     {['instagram', 'facebook', 'whatsapp'].map(p => {
                         const account = socialAccounts.find(a => a.platform === p);
                         const isPosted = asset.postedTo?.includes(p as SocialPlatform);
                         const isPosting = postingStates[`${asset.id}-${p}`];

                         return (
                            <button
                                key={p}
                                onClick={() => {
                                    if (userRole === 'Viewer') return;
                                    if (account?.connected && !isPosted) {
                                        handlePostClick(p as SocialPlatform, asset.id);
                                    } else if (!account?.connected) {
                                        // Viewers cannot connect accounts, admins can. Editors can post if connected.
                                        if (userRole === 'Admin') onConnectAccount(p as SocialPlatform);
                                    }
                                }}
                                disabled={userRole === 'Viewer' || isPosting || isPosted}
                                className={`p-2 rounded-full border transition-all ${
                                    isPosted ? 'bg-green-100 text-green-600 border-green-200' 
                                    : account?.connected ? 'bg-white text-slate-400 hover:text-amber-600 border-slate-100' 
                                    : 'bg-slate-50 text-slate-300 border-transparent'
                                } ${userRole === 'Viewer' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                title={account?.connected ? (isPosted ? t.assets.social.posted : t.assets.social.post) : (userRole === 'Admin' ? t.assets.social.connect : 'Connect (Admin Only)')}
                            >
                                {isPosting ? (
                                    <div className="w-4 h-4 border-2 border-slate-300 border-t-amber-500 rounded-full animate-spin"></div>
                                ) : (
                                    <>
                                        {p === 'instagram' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>}
                                        {p === 'facebook' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 2h-3a5 5 0 00-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 011-1h3z"></path></svg>}
                                        {p === 'whatsapp' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z"></path></svg>}
                                    </>
                                )}
                            </button>
                         );
                     })}
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default AssetGenerator;

import React, { useState } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset, GenerationStyle, AspectRatio, SocialAccount, SocialPlatform, Product, Role } from './types';
import * as aiService from './geminiService';
import { socialService } from './socialService';
import Landing from './components/Landing';
import Auth from './components/Auth';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';
import BrandSettings from './components/BrandSettings';
import { translations, Language } from './i18n';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('landing');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [lang, setLang] = useState<Language>('fr');
  const [userRole, setUserRole] = useState<Role>('Admin');

  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Middle-class urban professionals',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA',
    defaultStyle: 'natural'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [socialAccounts, setSocialAccounts] = useState<SocialAccount[]>([
    { platform: 'instagram', connected: false },
    { platform: 'facebook', connected: false },
    { platform: 'whatsapp', connected: false }
  ]);

  const t = translations[lang];

  const handleConnectAccount = async (platform: SocialPlatform) => {
    setLoading(true);
    setLoadingMessage(`Connecting to ${platform}...`);
    try {
        const success = await socialService.connectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: true } : acc));
        }
    } catch (e) {
        console.error(e);
        alert("Failed to connect account.");
    } finally {
        setLoading(false);
    }
  };

  const handleDisconnectAccount = async (platform: SocialPlatform) => {
    try {
        const success = await socialService.disconnectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: false } : acc));
        }
    } catch (e) {
        console.error(e);
    }
  };

  const handlePostAsset = async (platform: SocialPlatform, assetId: string): Promise<boolean> => {
    const asset = assets.find(a => a.id === assetId);
    if (!asset) return false;

    // Local loading is handled in AssetGenerator, but we update state here
    try {
        const success = await socialService.postAsset(platform, assetId, asset);
        if (success) {
             setAssets(prev => prev.map(a => a.id === assetId ? { ...a, postedTo: [...(a.postedTo || []), platform] } : a));
        }
        return success;
    } catch (e) {
        console.error(e);
        alert("Failed to post asset.");
        return false;
    }
  };

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage(t.loading.strategy);
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          campaignId: campaign.id,
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);

      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);

      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        campaignId: selectedCampaign.id,
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen gradient-bg text-slate-900 selection:bg-amber-200 flex flex-col">
      {step !== 'landing' && step !== 'auth' && (
        <header className="px-6 py-4 glass sticky top-0 z-50 flex justify-between items-center shadow-lg border-b border-white/20">
          <div className="flex items-center gap-3">
            <div className="w-12 h-12 bg-amber-600 rounded-2xl flex items-center justify-center text-white shadow-xl rotate-3">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
            </div>
            <div>
              <h1 className="text-xl font-black tracking-tight leading-none">AfriBrand <span className="text-amber-600">AI</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{t.tagline}</p>
            </div>
          </div>
          <div className="flex gap-4 items-center">
             <div className="flex bg-white/50 rounded-lg p-1 border border-slate-200">
                <button 
                  onClick={() => setLang('en')} 
                  className={`px-2 py-1 text-xs font-bold rounded-md transition-all ${lang === 'en' ? 'bg-amber-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  EN
                </button>
                <button 
                  onClick={() => setLang('fr')} 
                  className={`px-2 py-1 text-xs font-bold rounded-md transition-all ${lang === 'fr' ? 'bg-amber-600 text-white shadow-sm' : 'text-slate-500 hover:text-slate-900'}`}
                >
                  FR
                </button>
             </div>

              {step === 'assets' && (
                  <button 
                      onClick={() => setStep('calendar')}
                      className="px-4 py-2 bg-white/50 hover:bg-white text-slate-700 rounded-xl text-xs font-bold border border-slate-200 transition-all flex items-center gap-2"
                  >
                      <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                      {t.calendar}
                  </button>
              )}

              {step !== 'welcome' && (
                <>
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2 rounded-xl transition-all ${step === 'settings' ? 'bg-slate-900 text-white' : 'bg-white text-slate-500 hover:text-amber-600'}`}
                      title="Settings & Team"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                    <button 
                        onClick={() => setStep('welcome')}
                        className="px-4 py-2 bg-amber-600 text-white rounded-xl text-xs font-bold shadow-lg shadow-amber-600/20 hover:bg-amber-700 transition-all"
                    >
                        {t.reset}
                    </button>
                </>
              )}
          </div>
        </header>
      )}

      <main className={`flex-1 ${step === 'landing' || step === 'auth' ? '' : 'max-w-6xl mx-auto w-full p-6'}`}>
        {loading && (
          <div className="fixed inset-0 bg-white/80 backdrop-blur-xl z-[100] flex flex-col items-center justify-center text-center p-8">
            <div className="relative">
                <div className="w-24 h-24 border-4 border-amber-600 border-t-transparent rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center font-bold text-amber-600">A</div>
            </div>
            <h3 className="text-3xl font-black text-slate-800 mt-8 mb-2">{loadingMessage}</h3>
            <p className="text-slate-500 max-w-sm">{t.loading.generic}</p>
          </div>
        )}

        {step === 'landing' && <Landing onStart={() => setStep('auth')} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={handleConnectAccount} onDisconnectAccount={handleDisconnectAccount} onBack={() => setStep('welcome')} userRole={userRole} onSwitchRole={setUserRole} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} assets={assets} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} userRole={userRole} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={handleConnectAccount}
            onPostAsset={handlePostAsset}
            userRole={userRole}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
            userRole={userRole}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      <footer className="p-8 bg-slate-900 text-slate-400 text-center border-t border-slate-800">
        <div className="max-w-6xl mx-auto space-y-4">
          <div className="flex justify-center gap-8 mb-4">
            <a href="#" className="hover:text-white transition-colors">Vision</a>
            <a href="#" className="hover:text-white transition-colors">Pricing</a>
            <a href="#" className="hover:text-white transition-colors">Terms</a>
            <a href="#" className="hover:text-white transition-colors">Privacy</a>
          </div>
          <p className="text-xs uppercase tracking-[0.2em] font-bold">
            &copy; 2025 AfriBrand AI • Owned by Malthus AMETEPE
          </p>
          <p className="text-[10px] opacity-50 max-w-lg mx-auto leading-relaxed">
            High-end marketing automation for African SMEs. Powered by Gemini Cultural Intelligence. Optimized for low-bandwidth environments. Built with precision for the future of local commerce.
          </p>
        </div>
      </footer>
    </div>
  );
};

