interface CampaignPlannerProps {
  campaigns: Campaign[];
  assets: Asset[]; // Receive assets to include in export
  onSelect: (campaign: Campaign) => void;
  t: any;
  country?: string;
  userRole: Role;
}

const CampaignPlanner: React.FC<CampaignPlannerProps> = ({ campaigns, assets = [], onSelect, t, country, userRole }) => {
  const scheduleRecommendation = socialService.getRegionSchedule(country || 'Senegal');

  const exportToCSV = (e: React.MouseEvent) => {
    e.stopPropagation();
    const headers = ["Campaign Title", "Concept", "Cultural Hook", "Suggested Platforms"];
    const rows = campaigns.map(c => [
      `"${c.title.replace(/"/g, '""')}"`,
      `"${c.concept.replace(/"/g, '""')}"`,
      `"${c.culturalHook.replace(/"/g, '""')}"`,
      `"${c.suggestedPlatforms.join(", ")}"`
    ]);

    const csvContent = "data:text/csv;charset=utf-8," 
      + headers.join(",") + "\n"
      + rows.map(r => r.join(",")).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "afribrand_campaign_ideas.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportCampaignJSON = (e: React.MouseEvent, campaign: Campaign) => {
    e.stopPropagation();
    const relatedAssets = assets.filter(a => a.campaignId === campaign.id);
    const campaignData = {
        ...campaign,
        generatedAssets: relatedAssets.map(a => ({
            type: a.type,
            style: a.style,
            headline: a.headline,
            caption: a.caption,
            language: a.language,
            imageUrl: a.imageUrl,
            videoUrl: a.videoUrl
        }))
    };

    const jsonContent = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify(campaignData, null, 2));
    const link = document.createElement("a");
    link.setAttribute("href", jsonContent);
    link.setAttribute("download", `campaign_${campaign.id}_details.json`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const shareCampaign = async (e: React.MouseEvent, campaign: Campaign) => {
    e.stopPropagation();
    const shareData = {
      title: campaign.title,
      text: `Check out this campaign idea: ${campaign.title} - ${campaign.concept}`,
      url: window.location.href
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      alert("Sharing not supported on this browser.");
    }
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex flex-col md:flex-row items-center justify-between gap-4">
        <div className="text-left">
