            </div>

            <div className={`mt-8 flex items-center font-bold text-sm ${userRole === 'Viewer' ? 'text-slate-300 cursor-not-allowed' : 'text-amber-600 group-hover:translate-x-1 transition-transform'}`}>
                {userRole === 'Viewer' ? 'View Only' : t.planner.generate} {userRole !== 'Viewer' && <span className="ml-2">→</span>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default CampaignPlanner;

import React, { useState } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset, GenerationStyle, AspectRatio, SocialAccount, SocialPlatform, Product, Role } from './types';
import * as aiService from './geminiService';
import { socialService } from './socialService';
import Landing from './components/Landing';
import Auth from './components/Auth';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';
import BrandSettings from './components/BrandSettings';
import { translations, Language } from './i18n';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('landing');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [lang, setLang] = useState<Language>('fr');
  const [userRole, setUserRole] = useState<Role>('Admin');

  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Middle-class urban professionals',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA',
    defaultStyle: 'natural'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [socialAccounts, setSocialAccounts] = useState<SocialAccount[]>([
    { platform: 'instagram', connected: false },
    { platform: 'facebook', connected: false },
    { platform: 'whatsapp', connected: false }
  ]);

  const t = translations[lang];

  const handleConnectAccount = async (platform: SocialPlatform) => {
    setLoading(true);
    setLoadingMessage(`Connecting to ${platform}...`);
    try {
        const success = await socialService.connectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: true } : acc));
        }
    } catch (e) {
        console.error(e);
        alert("Failed to connect account.");
    } finally {
        setLoading(false);
    }
  };

  const handleDisconnectAccount = async (platform: SocialPlatform) => {
    try {
        const success = await socialService.disconnectAccount(platform);
        if (success) {
            setSocialAccounts(prev => prev.map(acc => acc.platform === platform ? { ...acc, connected: false } : acc));
        }
    } catch (e) {
        console.error(e);
    }
  };

  const handlePostAsset = async (platform: SocialPlatform, assetId: string): Promise<boolean> => {
    const asset = assets.find(a => a.id === assetId);
    if (!asset) return false;

    try {
        const success = await socialService.postAsset(platform, assetId, asset);
        if (success) {
             setAssets(prev => prev.map(a => a.id === assetId ? { ...a, postedTo: [...(a.postedTo || []), platform] } : a));
        }
        return success;
    } catch (e) {
        console.error(e);
        alert("Failed to post asset.");
        return false;
    }
  };

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage(t.loading.strategy);
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          campaignId: campaign.id,
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);

      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);

      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        campaignId: selectedCampaign.id,
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col ${step === 'landing' || step === 'auth' ? '' : 'afro-pattern'}`}>
      {/* Dynamic Header */}
      {step !== 'landing' && step !== 'auth' && (
        <header className="sticky top-0 z-50 glass-panel border-b border-white/40">
          <div className="max-w-7xl mx-auto px-6 h-16 flex justify-between items-center">
            <div className="flex items-center gap-3 cursor-pointer" onClick={() => setStep('welcome')}>
              <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-brand-600/30">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
              </div>
              <span className="text-lg font-bold tracking-tight text-slate-900">AfriBrand<span className="text-brand-600">.AI</span></span>
            </div>

            <div className="flex items-center gap-6">
               {/* Language Toggle */}
               <div className="flex bg-slate-100/50 rounded-full p-1 border border-slate-200/50">
                  <button onClick={() => setLang('en')} className={`px-3 py-1 text-xs font-semibold rounded-full transition-all ${lang === 'en' ? 'bg-white shadow-sm text-brand-900' : 'text-slate-500 hover:text-slate-900'}`}>EN</button>
                  <button onClick={() => setLang('fr')} className={`px-3 py-1 text-xs font-semibold rounded-full transition-all ${lang === 'fr' ? 'bg-white shadow-sm text-brand-900' : 'text-slate-500 hover:text-slate-900'}`}>FR</button>
               </div>

               <div className="h-6 w-px bg-slate-200"></div>

               {/* Navigation Actions */}
               <div className="flex items-center gap-2">
                  {step === 'assets' && (
                      <button 
                          onClick={() => setStep('calendar')}
                          className="p-2 text-slate-500 hover:text-brand-600 hover:bg-brand-50 rounded-full transition-all"
                          title={t.calendar}
                      >
                          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 7V3m8 4V3m-9 8h10M5 21h14a2 2 0 002-2V7a2 2 0 00-2-2H5a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>
                      </button>
                  )}

                  {step !== 'welcome' && (
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2 rounded-full transition-all ${step === 'settings' ? 'bg-brand-900 text-white' : 'text-slate-500 hover:text-brand-600 hover:bg-brand-50'}`}
                      title="Settings"
                    >
                        <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                  )}
               </div>
            </div>
          </div>
        </header>
      )}

      {/* Main Content Area */}
      <main className={`flex-1 ${step === 'landing' || step === 'auth' ? '' : 'max-w-7xl mx-auto w-full px-6 py-8'}`}>

        {/* Loading Overlay */}
        {loading && (
          <div className="fixed inset-0 z-[100] glass-panel-dark flex flex-col items-center justify-center text-center p-8 backdrop-blur-2xl">
            <div className="relative mb-8">
                <div className="w-20 h-20 border-2 border-white/10 rounded-full"></div>
                <div className="absolute inset-0 border-t-2 border-brand-500 rounded-full animate-spin"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <svg className="w-8 h-8 text-brand-500 animate-pulse" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                </div>
            </div>
            <h3 className="text-2xl font-bold text-white mb-2">{loadingMessage}</h3>
            <p className="text-slate-400 max-w-sm text-sm">{t.loading.generic}</p>
          </div>
        )}

        {/* View Routing */}
        {step === 'landing' && <Landing onStart={() => setStep('auth')} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={handleConnectAccount} onDisconnectAccount={handleDisconnectAccount} onBack={() => setStep('welcome')} userRole={userRole} onSwitchRole={setUserRole} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} assets={assets} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} userRole={userRole} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={handleConnectAccount}
            onPostAsset={handlePostAsset}
            userRole={userRole}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
            userRole={userRole}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      {/* Minimal Footer */}
      {step !== 'landing' && step !== 'auth' && (
        <footer className="py-8 text-center text-slate-400 border-t border-slate-200/60 bg-white/50 backdrop-blur-sm">
          <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4 text-xs font-medium">
             <p className="tracking-wide">© 2025 AFRIBRAND AI • PROPRIÉTÉ DE MALTHUS AMETEPE</p>
             <div className="flex gap-6">
                <a href="#" className="hover:text-brand-600 transition-colors">Support</a>
                <a href="#" className="hover:text-brand-600 transition-colors">Privacy</a>
                <a href="#" className="hover:text-brand-600 transition-colors">Terms</a>
             </div>
          </div>
        </footer>
      )}
    </div>
  );
};

