                  <div className="absolute top-4 right-4 bg-white/90 text-slate-900 px-3 py-1 rounded-full text-xs font-bold shadow-md z-20">
                     {asset.language}
                  </div>

                  {userRole !== 'Viewer' && (
                    <div className="absolute inset-0 bg-slate-900/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center p-8 backdrop-blur-md z-10">
                        <div className="text-center space-y-5 w-full">
                            <p className="text-white text-xs font-black uppercase tracking-widest">{asset.style} Style • {asset.aspectRatio}</p>
                            <div className="space-y-3">
                                <button 
                                    onClick={() => onEdit(asset)}
                                    className="w-full px-6 py-4 bg-white text-slate-900 rounded-2xl font-black shadow-xl hover:scale-105 transition-transform"
                                >
                                    {t.assets.refine}
                                </button>
                            </div>
                        </div>
                    </div>
                  )}
                </div>

                <div className="bg-white p-6 rounded-[2.5rem] shadow-xl border border-slate-100 relative group-hover:shadow-amber-100 transition-all">
                  <h4 className="text-xl font-black text-slate-900 mb-3 truncate mt-2">{asset.headline}</h4>
                  <p className="text-sm text-slate-500 mb-6 leading-relaxed line-clamp-3 font-medium">{asset.caption}</p>

                  <div className="flex items-center justify-between border-t border-slate-50 pt-5 gap-3">
                     {/* Social Posting Buttons */}
                     <div className="flex gap-2">
                     {['instagram', 'facebook', 'whatsapp'].map(p => {
                         const account = socialAccounts.find(a => a.platform === p);
                         const isPosted = asset.postedTo?.includes(p as SocialPlatform);
                         const isPosting = postingStates[`${asset.id}-${p}`];

                         return (
                            <button
                                key={p}
                                onClick={() => {
                                    if (userRole === 'Viewer') return;
                                    if (account?.connected && !isPosted) {
                                        handlePostClick(p as SocialPlatform, asset.id);
                                    } else if (!account?.connected) {
                                        if (userRole === 'Admin') onConnectAccount(p as SocialPlatform);
                                    }
                                }}
                                disabled={userRole === 'Viewer' || isPosting || isPosted}
                                className={`p-2 rounded-full border transition-all ${
                                    isPosted ? 'bg-green-100 text-green-600 border-green-200' 
                                    : account?.connected ? 'bg-white text-slate-400 hover:text-amber-600 border-slate-100' 
                                    : 'bg-slate-50 text-slate-300 border-transparent'
                                } ${userRole === 'Viewer' ? 'opacity-50 cursor-not-allowed' : ''}`}
                                title={account?.connected ? (isPosted ? t.assets.social.posted : t.assets.social.post) : (userRole === 'Admin' ? t.assets.social.connect : 'Connect (Admin Only)')}
                            >
                                {isPosting ? (
                                    <div className="w-4 h-4 border-2 border-slate-300 border-t-amber-500 rounded-full animate-spin"></div>
                                ) : (
                                    <>
                                        {p === 'instagram' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z"></path></svg>}
                                        {p === 'facebook' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M18 2h-3a5 5 0 00-5 5v3H7v4h3v8h4v-8h3l1-4h-4V7a1 1 0 011-1h3z"></path></svg>}
                                        {p === 'whatsapp' && <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 5a2 2 0 012-2h3.28a1 1 0 01.948.684l1.498 4.493a1 1 0 01-.502 1.21l-2.257 1.13a11.042 11.042 0 005.516 5.516l1.13-2.257a1 1 0 011.21-.502l4.493 1.498a1 1 0 01.684.949V19a2 2 0 01-2 2h-1C9.716 21 3 14.284 3 6V5z"></path></svg>}
                                    </>
                                )}
                            </button>
                         );
                     })}
                     </div>

                     <button
                        onClick={() => downloadAsset(asset)}
                        className="p-2 rounded-full border border-slate-100 bg-slate-50 text-slate-400 hover:bg-slate-100 hover:text-slate-600 transition-colors ml-auto"
                        title={t.assets.exportZip.replace(' (ZIP)', '')}
                     >
                        <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                     </button>
                  </div>
                </div>
              </div>
            ))}
           </div>
        </div>
      </div>
    </div>
  );
};

