      </div>

      {/* Smart Schedule Recommendation Banner */}
      <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 flex flex-col gap-6">
         <div className="flex items-center gap-4 border-b border-slate-50 pb-4">
