                 <p className="text-sm text-slate-500">{t.planner.optimalTime} <span className="font-bold text-amber-600">{scheduleRecommendation.region}</span></p>
             </div>
         </div>

         <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4">
            {/* General Best Times */}
            <div className="bg-slate-50 p-4 rounded-2xl">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3">Peak Activity</p>
