                <div className="flex flex-wrap gap-2">
                    {scheduleRecommendation.bestDays.map(day => (
                        <span key={day} className="px-2 py-1 bg-white rounded-lg text-xs font-bold text-slate-700 shadow-sm">{day}</span>
