    try {
      const zip = new JSZip();
      const safeTitle = campaign.title.replace(/[^a-z0-9]/gi, '_').toLowerCase() || 'campaign';
      const folder = zip.folder(`${safeTitle}_videos`);

      const promises = videoAssets.map(async (asset, index) => {
