export const generateVideoAd = async (campaign: Campaign, dna: BrandDNA, ratio: AspectRatio = '9:16', mode: VideoQualityMode = 'fast'): Promise<string> => {
  // Always create a new instance with the latest API key from env (which might be injected via window.aistudio)
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const modelName = mode === 'high-quality' ? 'veo-3.1-generate-preview' : 'veo-3.1-fast-generate-preview';

  let veoRatio = ratio;
  if (ratio === '1:1' || ratio === '4:5') veoRatio = '9:16'; 
  if (ratio === '1.91:1') veoRatio = '16:9'; 

  const prompt = `High-end social media commercial video for ${dna.name}. 
  Concept: ${campaign.concept}. 
  Style: Luxury modern African aesthetic. 
  Vibrant colors: ${dna.colors.join(', ')}. 
  Desired Output Aspect Ratio: ${ratio}.
  (Technical: Generating in ${veoRatio}).`;

  let operation = await ai.models.generateVideos({
    model: modelName,
    prompt: prompt,
    config: {
      numberOfVideos: 1,
      resolution: mode === 'high-quality' ? '1080p' : '720p',
      aspectRatio: veoRatio as any
    }
  });

  while (!operation.done) {
    // Polling interval
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({operation: operation});
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  if (!downloadLink) throw new Error("Video generation failed.");

  const fetchResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const blob = await fetchResponse.blob();
  return URL.createObjectURL(blob);
};

import React, { useState } from 'react';
import { BrandDNA } from '../types';
import * as aiService from '../geminiService';

interface BrandDNAViewProps {
  dna: BrandDNA;
  onNext: () => void;
  t: any;
}

const BrandDNAView: React.FC<BrandDNAViewProps> = ({ dna, onNext, t }) => {
  const [keywords, setKeywords] = useState<string[]>(dna.keywords);
  const [newKeyword, setNewKeyword] = useState('');
  const [imageStyle, setImageStyle] = useState(dna.imageStyle);
  const [refiningStyle, setRefiningStyle] = useState(false);
  const [refinementInput, setRefinementInput] = useState('');
  const [showRefiner, setShowRefiner] = useState(false);

  const exportDNA = () => {
    const jsonContent = "data:text/json;charset=utf-8," + encodeURIComponent(JSON.stringify({ ...dna, keywords, imageStyle }, null, 2));
    const link = document.createElement("a");
    link.setAttribute("href", jsonContent);
    link.setAttribute("download", `brand_dna_${dna.name.replace(/[^a-z0-9]/gi, '_').toLowerCase()}.json`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const exportInfographic = () => {
    window.print(); // Infographic is achieved via a dedicated @media print stylesheet in global or just clean layout
  };

  const addKeyword = (e: React.FormEvent) => {
    e.preventDefault();
    if (newKeyword.trim() && !keywords.includes(newKeyword.trim())) {
      setKeywords([...keywords, newKeyword.trim()]);
      setNewKeyword('');
    }
  };

  const removeKeyword = (kw: string) => {
    setKeywords(keywords.filter(k => k !== kw));
  };

  const handleRefineStyle = async () => {
    if (!refinementInput.trim()) return;
    setRefiningStyle(true);
    try {
      const refined = await aiService.refineImageStyle(imageStyle, refinementInput, dna);
      setImageStyle(refined);
      setRefinementInput('');
      setShowRefiner(false);
    } catch (err) {
      console.error(err);
    } finally {
      setRefiningStyle(false);
    }
  };

  return (
