    setLoading(true);
    setLoadingMessage(t.loading.strategy);
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          campaignId: campaign.id,
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);
      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);
      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        campaignId: selectedCampaign.id,
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isLight ? 'bg-slate-50 text-slate-900 light-theme' : 'bg-brand-950 text-slate-50'}`}>

      <div className="fixed inset-0 pointer-events-none z-0 afro-pattern opacity-100"></div>

      {step !== 'landing' && step !== 'auth' && (
        <header className={`sticky top-0 z-50 border-b transition-all ${isLight ? 'bg-white/80 border-slate-200/60 backdrop-blur-xl' : 'glass-panel border-white/5'}`}>
          <div className="max-w-7xl mx-auto px-6 h-18 flex justify-between items-center py-4">
            <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setStep('welcome')}>
              <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-brand-600/20 group-hover:rotate-12 transition-transform duration-300">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
              </div>
              <div>
                <span className={`text-lg font-bold tracking-tight ${isLight ? 'text-slate-900' : 'text-white'}`}>AfriBrand<span className="text-brand-600">.AI</span></span>
                <p className="text-[10px] font-medium opacity-50 uppercase tracking-widest leading-none">Enterprise</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className={`flex rounded-full p-1 border ${isLight ? 'bg-slate-100 border-slate-200' : 'bg-white/5 border-white/10'}`}>
                  <button onClick={() => setLang('en')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>EN</button>
                  <button onClick={() => setLang('fr')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'fr' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>FR</button>
               </div>

               <div className={`h-8 w-px ${isLight ? 'bg-slate-200' : 'bg-white/10'}`}></div>

               <div className="flex items-center gap-3">
                  {deferredPrompt && (
                    <button 
                      onClick={installApp}
                      className="p-2.5 rounded-full bg-brand-600 text-white shadow-lg shadow-brand-600/30 animate-bounce"
                      title="Install App"
                    >
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4"></path></svg>
                    </button>
                  )}

                  {step !== 'welcome' && (
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2.5 rounded-full transition-all group ${isLight ? 'hover:bg-slate-100 text-slate-500' : 'hover:bg-white/10 text-slate-400 hover:text-white'}`}
                      title="Settings"
                    >
                        <svg className="w-5 h-5 group-hover:rotate-90 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                  )}
               </div>
            </div>
          </div>
        </header>
      )}

      <main className={`flex-1 relative z-10 ${step === 'landing' || step === 'auth' ? '' : 'max-w-7xl mx-auto w-full px-6 py-10'}`}>
        {loading && (
          <div className="fixed inset-0 z-[100] bg-brand-950/80 backdrop-blur-2xl flex flex-col items-center justify-center text-center p-8 transition-opacity duration-300">
            <div className="relative mb-8">
                <div className="w-24 h-24 border-2 border-white/5 rounded-full absolute inset-0"></div>
                <div className="w-24 h-24 border-t-2 border-brand-500 rounded-full animate-spin absolute inset-0"></div>
                <div className="w-16 h-16 border-b-2 border-amber-500 rounded-full animate-spin absolute inset-4 direction-reverse"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white animate-pulse">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                   </div>
                </div>
            </div>
            <h3 className="text-2xl font-bold text-white mb-2 tracking-tight">{loadingMessage}</h3>
            <p className="text-slate-400 max-w-sm text-sm font-medium">{t.loading.generic}</p>
          </div>
        )}

        {step === 'landing' && <Landing onStart={() => setStep('auth')} onInstall={installApp} canInstall={!!deferredPrompt} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={() => {}} onDisconnectAccount={() => {}} onBack={() => setStep('welcome')} userRole={userRole} onSwitchRole={setUserRole} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} assets={assets} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} userRole={userRole} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={() => {}}
            onPostAsset={() => Promise.resolve(true)}
            userRole={userRole}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
            userRole={userRole}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      {/* Persistent PWA Install Banner */}
      {deferredPrompt && step !== 'landing' && step !== 'auth' && (
        <div className="fixed bottom-6 left-6 right-6 md:left-auto md:right-6 md:w-96 z-[60] animate-in slide-in-from-bottom duration-500">
           <div className="glass-panel p-5 rounded-[2rem] border-brand-500/30 flex items-center justify-between gap-4 shadow-[0_20px_50px_rgba(0,0,0,0.5)]">
              <div className="flex items-center gap-3">
                  <div className="w-12 h-12 bg-brand-600 rounded-2xl flex items-center justify-center text-white shadow-lg">
                    <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                  </div>
                  <div>
                    <h4 className="text-sm font-bold text-white">Installer l'App</h4>
                    <p className="text-[10px] text-slate-400 font-medium">Accès rapide & usage hors-ligne</p>
                  </div>
              </div>
              <button 
                onClick={installApp}
                className="px-5 py-2.5 bg-brand-600 text-white rounded-xl text-xs font-bold hover:bg-brand-500 transition-all shadow-lg"
              >
                Installer
              </button>
           </div>
        </div>
      )}

      {step !== 'landing' && step !== 'auth' && (
        <footer className={`py-8 text-center border-t backdrop-blur-sm ${isLight ? 'bg-white/50 border-slate-200/60 text-slate-500' : 'bg-brand-900/30 border-white/5 text-slate-500'}`}>
          <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4 text-xs font-semibold uppercase tracking-wider">
             <p>© 2025 AfriBrand AI • Propriété de Malthus AMETEPE</p>
             <div className="flex gap-6 items-center">
                {isInstalled && <span className="flex items-center gap-1.5 text-green-500"><div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse"></div> App Installée</span>}
                <a href="#" className="hover:text-brand-600 transition-colors">Support</a>
                <a href="#" className="hover:text-brand-600 transition-colors">Privacy</a>
             </div>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SocialAccount, SocialPlatform, TeamMember, ActivityLog, Role } from '../types';
import { socialService } from '../socialService';

interface BrandSettingsProps {
  socialAccounts: SocialAccount[];
  onConnectAccount: (platform: SocialPlatform) => void;
  onDisconnectAccount: (platform: SocialPlatform) => void;
  onBack: () => void;
  userRole: Role;
  onSwitchRole: (role: Role) => void;
}

const BrandSettings: React.FC<BrandSettingsProps> = ({ socialAccounts, onConnectAccount, onDisconnectAccount, onBack, userRole, onSwitchRole }) => {
  const [activeTab, setActiveTab] = useState<'team' | 'integrations'>('team');
  const [members, setMembers] = useState<TeamMember[]>(socialService.getTeamMembers());
  const [activities, setActivities] = useState<ActivityLog[]>(socialService.getActivities());
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>('Editor');
  const [catalogSynced, setCatalogSynced] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  const isStandalone = window.matchMedia('(display-mode: standalone)').matches || (window.navigator as any).standalone;

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inviteEmail) return;
    const newMember: TeamMember = {
      id: Math.random().toString(36).substr(2, 9),
      name: inviteEmail.split('@')[0],
      email: inviteEmail,
      role: inviteRole,
      avatar: inviteEmail.substring(0, 2).toUpperCase()
    };
    setMembers([...members, newMember]);
    setActivities([
        { id: Math.random().toString(), user: 'You', action: `Invited ${inviteEmail} as ${inviteRole}`, timestamp: 'Just now', type: 'creation' },
        ...activities
    ]);
    setInviteEmail('');
  };

  const handleRemoveMember = (id: string, name: string) => {
    setMembers(members.filter(m => m.id !== id));
    setActivities([
        { id: Math.random().toString(), user: 'You', action: `Removed ${name} from team`, timestamp: 'Just now', type: 'edit' },
        ...activities
    ]);
  };

  const handleSyncCatalog = () => {
    setIsSyncing(true);
    setTimeout(() => {
        setCatalogSynced(true);
        setIsSyncing(false);
        setActivities([
            { id: Math.random().toString(), user: 'You', action: 'Synced WhatsApp Catalog', timestamp: 'Just now', type: 'connection' },
            ...activities
        ]);
    }, 2000);
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-right duration-300">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
            </button>
            <h2 className="text-3xl font-black text-slate-900">Brand HQ Settings</h2>
        </div>

        <div className="flex items-center gap-3 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2">View As:</span>
            <div className="flex gap-1">
                {(['Admin', 'Editor', 'Viewer'] as Role[]).map((r) => (
                    <button
                        key={r}
                        onClick={() => onSwitchRole(r)}
                        className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${userRole === r ? 'bg-amber-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'}`}
                    >
                        {r}
                    </button>
                ))}
            </div>
        </div>
      </div>

      <div className="flex gap-6 border-b border-slate-200">
        <button 
            onClick={() => setActiveTab('team')}
            className={`pb-4 px-2 font-bold text-sm transition-all ${activeTab === 'team' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            Team Collaboration
        </button>
        <button 
            onClick={() => setActiveTab('integrations')}
            className={`pb-4 px-2 font-bold text-sm transition-all ${activeTab === 'integrations' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            Integrations & PWA
        </button>
      </div>

      {activeTab === 'team' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-8">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Team Members</h3>
                    <div className="space-y-4">
                        {members.map(member => (
                            <div key={member.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl">
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center font-bold text-sm">
                                        {member.avatar}
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-900 text-sm">{member.name}</p>
                                        <p className="text-xs text-slate-500">{member.email}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-4">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${member.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                        {member.role}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>

                    {userRole === 'Admin' ? (
                        <div className="mt-8 pt-8 border-t border-slate-100">
                            <h4 className="text-sm font-bold text-slate-900 mb-4">Invite New Member</h4>
                            <form onSubmit={handleInvite} className="flex flex-col sm:flex-row gap-4">
                                <input 
                                    type="email" 
                                    placeholder="colleague@agency.com" 
                                    className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-amber-500 text-sm"
                                    value={inviteEmail}
                                    onChange={(e) => setInviteEmail(e.target.value)}
                                    required
                                />
                                <button type="submit" className="px-6 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-colors">
                                    Send Invite
                                </button>
                            </form>
                        </div>
                    ) : (
                        <div className="mt-8 pt-8 border-t border-slate-100 text-center text-slate-400 text-sm">
                            <p>You must be an Admin to invite new members.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className="lg:col-span-1">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 h-full">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Activity Log</h3>
                    <div className="space-y-6 relative before:absolute before:left-4 before:top-8 before:bottom-0 before:w-0.5 before:bg-slate-100">
                        {activities.map((log) => (
                            <div key={log.id} className="relative pl-10">
                                <div className={`absolute left-2.5 top-1.5 w-3 h-3 rounded-full border-2 border-white shadow-sm ${
                                    log.type === 'creation' ? 'bg-green-500' : 
                                    log.type === 'connection' ? 'bg-blue-500' :
                                    log.type === 'edit' ? 'bg-red-500' :
                                    log.type === 'export' ? 'bg-amber-500' : 'bg-slate-400'
                                }`}></div>
                                <p className="text-xs text-slate-500 mb-1">{log.timestamp}</p>
                                <p className="text-sm font-medium text-slate-900">{log.action}</p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}

      {activeTab === 'integrations' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Application PWA</h3>
                <div className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex flex-col gap-4">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className="w-12 h-12 rounded-xl bg-brand-600 flex items-center justify-center text-white">
                                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 18h.01M8 21h8a2 2 0 002-2V5a2 2 0 00-2-2H8a2 2 0 00-2 2v14a2 2 0 002 2z"></path></svg>
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-900">Statut de l'App</h4>
                                <p className="text-xs text-slate-500">{isStandalone ? 'Mode Application (Installée)' : 'Mode Navigateur Web'}</p>
                            </div>
                        </div>
                        {isStandalone ? (
                           <span className="px-3 py-1 bg-green-100 text-green-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-green-200">Prêt</span>
                        ) : (
                           <span className="px-3 py-1 bg-amber-100 text-amber-700 rounded-full text-[10px] font-black uppercase tracking-widest border border-amber-200">Installable</span>
                        )}
                    </div>
                    <p className="text-xs text-slate-500 leading-relaxed italic">
                        Une fois installée, l'application se lance sans interface de navigateur, offre un chargement plus rapide et peut fonctionner hors-ligne pour consulter vos assets.
                    </p>
                </div>

                <h3 className="text-xl font-bold text-slate-900">Social Accounts</h3>
                {socialAccounts.map(account => (
                    <div key={account.platform} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white ${
                                account.platform === 'instagram' ? 'bg-gradient-to-tr from-yellow-400 via-red-500 to-purple-500' :
                                account.platform === 'facebook' ? 'bg-blue-600' : 'bg-green-500'
                            }`}>
                                <span>{account.platform.charAt(0).toUpperCase()}</span>
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-900 capitalize">{account.platform}</h4>
                                <p className="text-xs text-slate-500">{account.connected ? 'Connected' : 'Not Connected'}</p>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Commerce & Catalog</h3>
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-12 h-12 bg-green-100 text-green-600 rounded-xl flex items-center justify-center">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-900">WhatsApp Catalog</h4>
                            <p className="text-xs text-slate-500">{catalogSynced ? 'Synced: 4 Products' : 'Sync Required'}</p>
                        </div>
                    </div>

                    <button 
                        onClick={handleSyncCatalog}
                        disabled={isSyncing}
                        className="w-full py-3 bg-green-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-green-700 transition-all disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {isSyncing ? 'Syncing...' : 'Sync Catalog Now'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default BrandSettings;

import React, { useState, useEffect } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset, GenerationStyle, AspectRatio, SocialAccount, SocialPlatform, Product, Role } from './types';
import * as aiService from './geminiService';
import { socialService } from './socialService';
import Landing from './components/Landing';
import Auth from './components/Auth';
import Welcome from './components/Welcome';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';
import BrandSettings from './components/BrandSettings';
import { translations, Language } from './i18n';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('landing');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [lang, setLang] = useState<Language>('fr');
  const [userRole, setUserRole] = useState<Role>('Admin');
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Middle-class urban professionals',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA',
    defaultStyle: 'natural'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [socialAccounts, setSocialAccounts] = useState<SocialAccount[]>([
    { platform: 'instagram', connected: false },
    { platform: 'facebook', connected: false },
    { platform: 'whatsapp', connected: false }
  ]);

  const t = translations[lang];
  const isLight = theme === 'light';

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setLoading(true);
    setLoadingMessage(t.loading.strategy);
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      setStep('dna');
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
    } finally {
      setLoading(false);
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          campaignId: campaign.id,
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);
      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);
      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        campaignId: selectedCampaign.id,
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isLight ? 'bg-slate-50 text-slate-900 light-theme' : 'bg-brand-950 text-slate-50'}`}>

      <div className="fixed inset-0 pointer-events-none z-0 afro-pattern opacity-100"></div>

      {step !== 'landing' && step !== 'auth' && (
        <header className={`sticky top-0 z-50 border-b transition-all ${isLight ? 'bg-white/80 border-slate-200/60 backdrop-blur-xl' : 'glass-panel border-white/5'}`}>
          <div className="max-w-7xl mx-auto px-6 h-18 flex justify-between items-center py-4">
            <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setStep('welcome')}>
              <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-brand-600/20 group-hover:rotate-12 transition-transform duration-300">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
              </div>
              <div>
                <span className={`text-lg font-bold tracking-tight ${isLight ? 'text-slate-900' : 'text-white'}`}>AfriBrand<span className="text-brand-600">.AI</span></span>
                <p className="text-[10px] font-medium opacity-50 uppercase tracking-widest leading-none">Enterprise</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className={`flex rounded-full p-1 border ${isLight ? 'bg-slate-100 border-slate-200' : 'bg-white/5 border-white/10'}`}>
                  <button onClick={() => setLang('en')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>EN</button>
                  <button onClick={() => setLang('fr')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'fr' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>FR</button>
               </div>

               <div className={`h-8 w-px ${isLight ? 'bg-slate-200' : 'bg-white/10'}`}></div>

               <div className="flex items-center gap-3">
                  {step !== 'welcome' && (
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2.5 rounded-full transition-all group ${isLight ? 'hover:bg-slate-100 text-slate-500' : 'hover:bg-white/10 text-slate-400 hover:text-white'}`}
                      title="Settings"
                    >
                        <svg className="w-5 h-5 group-hover:rotate-90 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                  )}
               </div>
            </div>
          </div>
        </header>
      )}

      <main className={`flex-1 relative z-10 ${step === 'landing' || step === 'auth' ? '' : 'max-w-7xl mx-auto w-full px-6 py-10'}`}>
        {loading && (
          <div className="fixed inset-0 z-[100] bg-brand-950/80 backdrop-blur-2xl flex flex-col items-center justify-center text-center p-8 transition-opacity duration-300">
            <div className="relative mb-8">
                <div className="w-24 h-24 border-2 border-white/5 rounded-full absolute inset-0"></div>
                <div className="w-24 h-24 border-t-2 border-brand-500 rounded-full animate-spin absolute inset-0"></div>
                <div className="w-16 h-16 border-b-2 border-amber-500 rounded-full animate-spin absolute inset-4 direction-reverse"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white animate-pulse">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                   </div>
                </div>
            </div>
            <h3 className="text-2xl font-bold text-white mb-2 tracking-tight">{loadingMessage}</h3>
            <p className="text-slate-400 max-w-sm text-sm font-medium">{t.loading.generic}</p>
          </div>
        )}

        {step === 'landing' && <Landing onStart={() => setStep('auth')} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={() => {}} onDisconnectAccount={() => {}} onBack={() => setStep('welcome')} userRole={userRole} onSwitchRole={setUserRole} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} assets={assets} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} userRole={userRole} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={() => {}}
            onPostAsset={() => Promise.resolve(true)}
            userRole={userRole}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
            userRole={userRole}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      {step !== 'landing' && step !== 'auth' && (
        <footer className={`py-8 text-center border-t backdrop-blur-sm ${isLight ? 'bg-white/50 border-slate-200/60 text-slate-500' : 'bg-brand-900/30 border-white/5 text-slate-500'}`}>
          <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4 text-xs font-semibold uppercase tracking-wider">
             <p>© 2025 AfriBrand AI • Propriété de Malthus AMETEPE</p>
             <div className="flex gap-6 items-center">
                <a href="#" className="hover:text-brand-600 transition-colors">Support</a>
                <a href="#" className="hover:text-brand-600 transition-colors">Privacy</a>
             </div>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { SocialAccount, SocialPlatform, TeamMember, ActivityLog, Role } from '../types';
import { socialService } from '../socialService';

interface BrandSettingsProps {
  socialAccounts: SocialAccount[];
  onConnectAccount: (platform: SocialPlatform) => void;
  onDisconnectAccount: (platform: SocialPlatform) => void;
  onBack: () => void;
  userRole: Role;
  onSwitchRole: (role: Role) => void;
}

const BrandSettings: React.FC<BrandSettingsProps> = ({ socialAccounts, onConnectAccount, onDisconnectAccount, onBack, userRole, onSwitchRole }) => {
  const [activeTab, setActiveTab] = useState<'team' | 'integrations'>('team');
  const [members, setMembers] = useState<TeamMember[]>(socialService.getTeamMembers());
  const [activities, setActivities] = useState<ActivityLog[]>(socialService.getActivities());
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>('Editor');
  const [catalogSynced, setCatalogSynced] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inviteEmail) return;
    const newMember: TeamMember = {
      id: Math.random().toString(36).substr(2, 9),
      name: inviteEmail.split('@')[0],
      email: inviteEmail,
      role: inviteRole,
      avatar: inviteEmail.substring(0, 2).toUpperCase()
    };
    setMembers([...members, newMember]);
    setActivities([
        { id: Math.random().toString(), user: 'You', action: `Invited ${inviteEmail} as ${inviteRole}`, timestamp: 'Just now', type: 'creation' },
        ...activities
    ]);
    setInviteEmail('');
  };

  const handleSyncCatalog = () => {
    setIsSyncing(true);
    setTimeout(() => {
        setCatalogSynced(true);
        setIsSyncing(false);
        setActivities([
            { id: Math.random().toString(), user: 'You', action: 'Synced WhatsApp Catalog', timestamp: 'Just now', type: 'connection' },
            ...activities
        ]);
    }, 2000);
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-right duration-300">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
            </button>
            <h2 className="text-3xl font-black text-slate-900">Brand HQ Settings</h2>
        </div>

        <div className="flex items-center gap-3 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2">View As:</span>
            <div className="flex gap-1">
                {(['Admin', 'Editor', 'Viewer'] as Role[]).map((r) => (
                    <button
                        key={r}
                        onClick={() => onSwitchRole(r)}
                        className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${userRole === r ? 'bg-amber-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'}`}
                    >
                        {r}
                    </button>
                ))}
            </div>
        </div>
      </div>

      <div className="flex gap-6 border-b border-slate-200">
        <button 
            onClick={() => setActiveTab('team')}
            className={`pb-4 px-2 font-bold text-sm transition-all ${activeTab === 'team' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            Team Collaboration
        </button>
        <button 
            onClick={() => setActiveTab('integrations')}
            className={`pb-4 px-2 font-bold text-sm transition-all ${activeTab === 'integrations' ? 'text-amber-600 border-b-2 border-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
            Integrations
        </button>
      </div>

      {activeTab === 'team' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-8">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Team Members</h3>
                    <div className="space-y-4">
                        {members.map(member => (
                            <div key={member.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl">
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center font-bold text-sm">
                                        {member.avatar}
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-900 text-sm">{member.name}</p>
                                        <p className="text-xs text-slate-500">{member.email}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-4">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${member.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                        {member.role}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>

                    {userRole === 'Admin' ? (
                        <div className="mt-8 pt-8 border-t border-slate-100">
                            <h4 className="text-sm font-bold text-slate-900 mb-4">Invite New Member</h4>
                            <form onSubmit={handleInvite} className="flex flex-col sm:flex-row gap-4">
                                <input 
                                    type="email" 
                                    placeholder="colleague@agency.com" 
                                    className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-amber-500 text-sm"
                                    value={inviteEmail}
                                    onChange={(e) => setInviteEmail(e.target.value)}
                                    required
                                />
                                <button type="submit" className="px-6 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-colors">
                                    Send Invite
                                </button>
                            </form>
                        </div>
                    ) : (
                        <div className="mt-8 pt-8 border-t border-slate-100 text-center text-slate-400 text-sm">
                            <p>You must be an Admin to invite new members.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className="lg:col-span-1">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 h-full">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Activity Log</h3>
                    <div className="space-y-6 relative before:absolute before:left-4 before:top-8 before:bottom-0 before:w-0.5 before:bg-slate-100">
                        {activities.map((log) => (
                            <div key={log.id} className="relative pl-10">
                                <div className={`absolute left-2.5 top-1.5 w-3 h-3 rounded-full border-2 border-white shadow-sm ${
                                    log.type === 'creation' ? 'bg-green-500' : 
                                    log.type === 'connection' ? 'bg-blue-500' :
                                    log.type === 'edit' ? 'bg-red-500' :
                                    log.type === 'export' ? 'bg-amber-500' : 'bg-slate-400'
                                }`}></div>
                                <p className="text-xs text-slate-500 mb-1">{log.timestamp}</p>
                                <p className="text-sm font-medium text-slate-900">{log.action}</p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}

      {activeTab === 'integrations' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Social Accounts</h3>
                {socialAccounts.map(account => (
                    <div key={account.platform} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white ${
                                account.platform === 'instagram' ? 'bg-gradient-to-tr from-yellow-400 via-red-500 to-purple-500' :
                                account.platform === 'facebook' ? 'bg-blue-600' : 'bg-green-500'
                            }`}>
                                <span>{account.platform.charAt(0).toUpperCase()}</span>
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-900 capitalize">{account.platform}</h4>
                                <p className="text-xs text-slate-500">{account.connected ? 'Connected' : 'Not Connected'}</p>
                            </div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Commerce & Catalog</h3>
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-12 h-12 bg-green-100 text-green-600 rounded-xl flex items-center justify-center">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-900">WhatsApp Catalog</h4>
                            <p className="text-xs text-slate-500">{catalogSynced ? 'Synced: 4 Products' : 'Sync Required'}</p>
                        </div>
                    </div>

                    <button 
                        onClick={handleSyncCatalog}
                        disabled={isSyncing}
                        className="w-full py-3 bg-green-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-green-700 transition-all disabled:opacity-70 flex items-center justify-center gap-2"
                    >
                        {isSyncing ? 'Syncing...' : 'Sync Catalog Now'}
                    </button>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default BrandSettings;

import React, { useState, useEffect } from 'react';
import { AppStep, UserInput, BrandDNA, Campaign, Asset, GenerationStyle, AspectRatio, SocialAccount, SocialPlatform, Product, Role } from './types';
import * as aiService from './geminiService';
import { socialService } from './socialService';
import Landing from './components/Landing';
import Auth from './components/Auth';
import Welcome from './components/Welcome';
import AnalysisTransition from './components/AnalysisTransition';
import BrandDNAView from './components/BrandDNAView';
import CampaignPlanner from './components/CampaignPlanner';
import AssetGenerator from './components/AssetGenerator';
import AssetEditor from './components/AssetEditor';
import CalendarView from './components/CalendarView';
import BrandSettings from './components/BrandSettings';
import LegalView from './components/LegalView';
import { translations, Language } from './i18n';

const App: React.FC = () => {
  const [step, setStep] = useState<AppStep>('landing');
  const [loading, setLoading] = useState(false);
  const [loadingMessage, setLoadingMessage] = useState('');
  const [lang, setLang] = useState<Language>('fr');
  const [userRole, setUserRole] = useState<Role>('Admin');
  const [theme, setTheme] = useState<'dark' | 'light'>('dark');

  const [userInput, setUserInput] = useState<UserInput>({
    businessName: '',
    url: '',
    description: '',
    country: 'Senegal',
    targetAudience: 'Middle-class urban professionals',
    preferredLanguages: ['French', 'Wolof'],
    currency: 'FCFA',
    defaultStyle: 'natural'
  });
  const [dna, setDna] = useState<BrandDNA | null>(null);
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [assets, setAssets] = useState<Asset[]>([]);
  const [selectedAsset, setSelectedAsset] = useState<Asset | null>(null);
  const [socialAccounts, setSocialAccounts] = useState<SocialAccount[]>([
    { platform: 'instagram', connected: false },
    { platform: 'facebook', connected: false },
    { platform: 'whatsapp', connected: false }
  ]);

  const t = translations[lang];
  const isLight = theme === 'light';

  const startAnalysis = async (input: UserInput) => {
    setUserInput(input);
    setStep('analysis');
    try {
      const result = await aiService.analyzeBrandDNA(input);
      setDna(result);
      // Let the analysis animation play for at least 3 seconds
      setTimeout(() => setStep('dna'), 3500);
    } catch (error) {
      console.error(error);
      alert("Analysis failed. Check your API key.");
      setStep('welcome');
    }
  };

  const generateIdeas = async () => {
    if (!dna) return;
    setLoading(true);
    setLoadingMessage(t.loading.curating);
    try {
      const results = await aiService.generateCampaigns(dna, userInput);
      setCampaigns(results);
      setStep('ideation');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateCampaignAssets = async (campaign: Campaign, styleOverride?: GenerationStyle, ratio: AspectRatio = '1:1', product?: Product) => {
    if (!dna) return;
    setSelectedCampaign(campaign);
    setLoading(true);
    setLoadingMessage(t.loading.visuals);
    try {
      const style = styleOverride || userInput.defaultStyle || 'natural';
      const imageUrl = await aiService.generateAssetVisual(campaign, dna, 'post', style, ratio, product);

      const newAssetsPromises = userInput.preferredLanguages.map(async (language) => {
        const content = await aiService.generateAssetContent(campaign, dna, language, product);
        return {
          id: Math.random().toString(36).substr(2, 9),
          campaignId: campaign.id,
          type: ratio === '9:16' ? 'story' : 'post' as any,
          imageUrl,
          headline: content.headline,
          caption: content.caption,
          language: language,
          style,
          aspectRatio: ratio
        } as Asset;
      });

      const newAssets = await Promise.all(newAssetsPromises);
      setAssets(prev => [...prev, ...newAssets]);
      setStep('assets');
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const generateVideo = async (ratio: AspectRatio = '9:16', mode: 'fast' | 'high-quality' = 'fast') => {
    if (!dna || !selectedCampaign) return;

    // @ts-ignore
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      // @ts-ignore
      await window.aistudio.openSelectKey();
    }

    setLoading(true);
    setLoadingMessage(t.loading.video);
    try {
      const videoUrl = await aiService.generateVideoAd(selectedCampaign, dna, ratio, mode);
      const newVideoAsset: Asset = {
        id: Math.random().toString(36).substr(2, 9),
        campaignId: selectedCampaign.id,
        type: 'video',
        videoUrl,
        headline: selectedCampaign.title,
        caption: `Exclusive promo for ${selectedCampaign.title}`,
        language: userInput.preferredLanguages[0],
        style: 'natural',
        aspectRatio: ratio
      };
      setAssets(prev => [...prev, newVideoAsset]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={`min-h-screen flex flex-col transition-colors duration-500 ${isLight ? 'bg-slate-50 text-slate-900 light-theme' : 'bg-brand-950 text-slate-50'}`}>

      <div className="fixed inset-0 pointer-events-none z-0 afro-pattern opacity-100"></div>

      {step !== 'landing' && step !== 'auth' && step !== 'analysis' && (
        <header className={`sticky top-0 z-50 border-b transition-all ${isLight ? 'bg-white/80 border-slate-200/60 backdrop-blur-xl' : 'glass-panel border-white/5'}`}>
          <div className="max-w-7xl mx-auto px-6 h-18 flex justify-between items-center py-4">
            <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setStep('welcome')}>
              <div className="w-10 h-10 bg-brand-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-brand-600/20 group-hover:rotate-12 transition-transform duration-300">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
              </div>
              <div>
                <span className={`text-lg font-bold tracking-tight ${isLight ? 'text-slate-900' : 'text-white'}`}>AfriBrand<span className="text-brand-600">.AI</span></span>
                <p className="text-[10px] font-medium opacity-50 uppercase tracking-widest leading-none">Enterprise</p>
              </div>
            </div>

            <div className="flex items-center gap-6">
               <div className={`flex rounded-full p-1 border ${isLight ? 'bg-slate-100 border-slate-200' : 'bg-white/5 border-white/10'}`}>
                  <button onClick={() => setLang('en')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'en' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>EN</button>
                  <button onClick={() => setLang('fr')} className={`px-3 py-1 text-xs font-bold rounded-full transition-all ${lang === 'fr' ? (isLight ? 'bg-white shadow-sm text-brand-900' : 'bg-brand-600 text-white shadow-lg shadow-brand-600/20') : 'opacity-50 hover:opacity-100'}`}>FR</button>
               </div>

               <div className={`h-8 w-px ${isLight ? 'bg-slate-200' : 'bg-white/10'}`}></div>

               <div className="flex items-center gap-3">
                  {step !== 'welcome' && (
                    <button 
                      onClick={() => setStep('settings')}
                      className={`p-2.5 rounded-full transition-all group ${isLight ? 'hover:bg-slate-100 text-slate-500' : 'hover:bg-white/10 text-slate-400 hover:text-white'}`}
                      title="Settings"
                    >
                        <svg className="w-5 h-5 group-hover:rotate-90 transition-transform duration-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10.325 4.317c.426-1.756 2.924-1.756 3.35 0a1.724 1.724 0 002.573 1.066c1.543-.94 3.31.826 2.37 2.37a1.724 1.724 0 001.065 2.572c1.756.426 1.756 2.924 0 3.35a1.724 1.724 0 00-1.066 2.573c.94 1.543-.826 3.31-2.37 2.37a1.724 1.724 0 00-2.572 1.065c-.426 1.756-2.924 1.756-3.35 0a1.724 1.724 0 00-2.573-1.066c-1.543.94-3.31-.826-2.37-2.37a1.724 1.724 0 00-1.065-2.572c-1.756-.426-1.756-2.924 0-3.35a1.724 1.724 0 001.066-2.573c-.94-1.543.826-3.31 2.37-2.37.996.608 2.296.07 2.572-1.065z"></path><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z"></path></svg>
                    </button>
                  )}
               </div>
            </div>
          </div>
        </header>
      )}

      <main className={`flex-1 relative z-10 ${step === 'landing' || step === 'auth' || step === 'analysis' ? '' : 'max-w-7xl mx-auto w-full px-6 py-10'}`}>
        {loading && (
          <div className="fixed inset-0 z-[100] bg-brand-950/80 backdrop-blur-2xl flex flex-col items-center justify-center text-center p-8 transition-opacity duration-300">
            <div className="relative mb-8">
                <div className="w-24 h-24 border-2 border-white/5 rounded-full absolute inset-0"></div>
                <div className="w-24 h-24 border-t-2 border-brand-500 rounded-full animate-spin absolute inset-0"></div>
                <div className="w-16 h-16 border-b-2 border-amber-500 rounded-full animate-spin absolute inset-4 direction-reverse"></div>
                <div className="absolute inset-0 flex items-center justify-center">
                   <div className="w-8 h-8 bg-brand-600 rounded-lg flex items-center justify-center text-white animate-pulse">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                   </div>
                </div>
            </div>
            <h3 className="text-2xl font-bold text-white mb-2 tracking-tight">{loadingMessage}</h3>
            <p className="text-slate-400 max-w-sm text-sm font-medium">{t.loading.generic}</p>
          </div>
        )}

        {step === 'landing' && <Landing onStart={() => setStep('auth')} />}
        {step === 'auth' && <Auth onAuth={() => setStep('welcome')} />}
        {step === 'welcome' && <Welcome onStart={startAnalysis} t={t} />}
        {step === 'analysis' && <AnalysisTransition input={userInput} t={t} />}
        {step === 'settings' && <BrandSettings socialAccounts={socialAccounts} onConnectAccount={() => {}} onDisconnectAccount={() => {}} onBack={() => setStep('welcome')} userRole={userRole} onSwitchRole={setUserRole} />}
        {step === 'dna' && dna && <BrandDNAView dna={dna} onNext={generateIdeas} t={t} />}
        {step === 'ideation' && <CampaignPlanner campaigns={campaigns} assets={assets} onSelect={(c) => generateCampaignAssets(c)} t={t} country={userInput.country} userRole={userRole} />}
        {step === 'assets' && (
          <AssetGenerator 
            assets={assets} 
            dna={dna!}
            onEdit={(a) => { setSelectedAsset(a); setStep('editor'); }} 
            campaign={selectedCampaign!} 
            onGenerateVideo={generateVideo}
            onRegenerate={(style, ratio, product) => generateCampaignAssets(selectedCampaign!, style, ratio, product)}
            t={t}
            socialAccounts={socialAccounts}
            onConnectAccount={() => {}}
            onPostAsset={() => Promise.resolve(true)}
            userRole={userRole}
          />
        )}
        {step === 'editor' && selectedAsset && dna && (
          <AssetEditor 
            asset={selectedAsset} 
            dna={dna} 
            onSave={(a) => { setAssets(prev => prev.map(old => old.id === a.id ? a : old)); setSelectedAsset(a); }} 
            onBack={() => setStep('assets')}
            userRole={userRole}
          />
        )}
        {step === 'calendar' && <CalendarView campaigns={campaigns} onBack={() => setStep('assets')} />}
      </main>

      {step !== 'landing' && step !== 'auth' && step !== 'analysis' && (
        <footer className={`py-8 text-center border-t backdrop-blur-sm ${isLight ? 'bg-white/50 border-slate-200/60 text-slate-500' : 'bg-brand-900/30 border-white/5 text-slate-500'}`}>
          <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4 text-xs font-semibold uppercase tracking-wider">
             <p>© 2025 AfriBrand AI • Propriété de Malthus AMETEPE</p>
             <div className="flex gap-6 items-center">
                <a href="#" className="hover:text-brand-600 transition-colors">Support</a>
                <a href="#" className="hover:text-brand-600 transition-colors">Privacy</a>
             </div>
          </div>
        </footer>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { UserInput } from '../types';

interface AnalysisTransitionProps {
  input: UserInput;
  t: any;
}

const AnalysisTransition: React.FC<AnalysisTransitionProps> = ({ input, t }) => {
  const [progress, setProgress] = useState(0);
  const [currentAction, setCurrentAction] = useState('Initializing Analysis Engine...');

  const actions = [
    { threshold: 0, text: 'Scanning Brand Digital Footprint...' },
    { threshold: 15, text: 'Extracting Color Palette & Visual Markers...' },
    { threshold: 30, text: 'Identifying Local Cultural Slang & Hooks...' },
    { threshold: 45, text: 'Analyzing Regional Market Sentiment...' },
    { threshold: 60, text: 'Generating Editorial Voice & Tone...' },
    { threshold: 75, text: 'Curating Bespoke Visual Guidelines...' },
    { threshold: 90, text: 'Finalizing Brand DNA Profile...' },
  ];

  useEffect(() => {
    const timer = setInterval(() => {
      setProgress(prev => {
        const next = prev + 1;
        const action = actions.find(a => next >= a.threshold && next < (actions[actions.indexOf(a) + 1]?.threshold || 101));
        if (action) setCurrentAction(action.text);
        return next > 100 ? 100 : next;
      });
    }, 30);
    return () => clearInterval(timer);
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-brand-950 flex items-center justify-center p-6">
      <div className="absolute inset-0 afro-pattern opacity-20"></div>

      <div className="max-w-2xl w-full space-y-12 relative z-10 text-center">
        <div className="relative inline-block">
            <div className="w-32 h-32 border-4 border-white/5 rounded-[2rem] animate-pulse"></div>
            <div className="absolute inset-0 flex items-center justify-center">
                 <div className="w-16 h-16 bg-brand-600 rounded-2xl flex items-center justify-center text-white shadow-2xl shadow-brand-600/40 animate-bounce">
                    <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M13 10V3L4 14h7v7l9-11h-7z"></path></svg>
                 </div>
            </div>
            {/* Orbital rings */}
            <div className="absolute inset-[-20px] border border-white/10 rounded-full animate-[spin_10s_linear_infinite]"></div>
            <div className="absolute inset-[-40px] border border-brand-500/10 rounded-full animate-[spin_15s_linear_infinite_reverse]"></div>
        </div>

        <div className="space-y-4">
            <h2 className="text-3xl font-black text-white tracking-tight">Analyzing <span className="text-brand-500">{input.businessName}</span></h2>
            <p className="text-slate-500 font-mono text-xs uppercase tracking-[0.3em] h-4">{currentAction}</p>
        </div>

        <div className="space-y-6">
            <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden border border-white/5">
                <div 
                    className="h-full bg-gradient-to-r from-brand-600 to-amber-500 transition-all duration-300 ease-out"
                    style={{ width: `${progress}%` }}
                ></div>
            </div>
            <div className="flex justify-between text-[10px] font-black text-slate-500 uppercase tracking-widest">
                <span>0% Initiated</span>
                <span>{progress}% Optimized</span>
                <span>100% African DNA</span>
            </div>
        </div>

        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 opacity-40">
            {['Strategy', 'Visuals', 'Copy', 'Culture'].map((tag) => (
                <div key={tag} className="px-4 py-2 border border-white/10 rounded-xl text-[10px] font-bold text-white uppercase tracking-widest bg-white/5">
                    {tag} Loaded
                </div>
            ))}
        </div>
      </div>
    </div>
  );
};

export default AnalysisTransition;

import React, { useState } from 'react';
import { SocialAccount, SocialPlatform, TeamMember, ActivityLog, Role, Product } from '../types';
import { socialService } from '../socialService';

interface BrandSettingsProps {
  socialAccounts: SocialAccount[];
  onConnectAccount: (platform: SocialPlatform) => void;
  onDisconnectAccount: (platform: SocialPlatform) => void;
  onBack: () => void;
  userRole: Role;
  onSwitchRole: (role: Role) => void;
}

const BrandSettings: React.FC<BrandSettingsProps> = ({ socialAccounts, onConnectAccount, onDisconnectAccount, onBack, userRole, onSwitchRole }) => {
  const [activeTab, setActiveTab] = useState<'team' | 'integrations' | 'billing' | 'help'>('team');
  const [members, setMembers] = useState<TeamMember[]>(socialService.getTeamMembers());
  const [activities, setActivities] = useState<ActivityLog[]>(socialService.getActivities());
  const [inviteEmail, setInviteEmail] = useState('');
  const [inviteRole, setInviteRole] = useState<Role>('Editor');
  const [catalogSynced, setCatalogSynced] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [products, setProducts] = useState<Product[]>(socialService.getMockCatalog());

  const handleInvite = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inviteEmail) return;
    const newMember: TeamMember = {
      id: Math.random().toString(36).substr(2, 9),
      name: inviteEmail.split('@')[0],
      email: inviteEmail,
      role: inviteRole,
      avatar: inviteEmail.substring(0, 2).toUpperCase()
    };
    setMembers([...members, newMember]);
    setActivities([
        { id: Math.random().toString(), user: 'You', action: `Invited ${inviteEmail} as ${inviteRole}`, timestamp: 'Just now', type: 'creation' },
        ...activities
    ]);
    setInviteEmail('');
  };

  const handleSyncCatalog = () => {
    setIsSyncing(true);
    setTimeout(() => {
        setCatalogSynced(true);
        setIsSyncing(false);
        setActivities([
            { id: Math.random().toString(), user: 'You', action: 'Synced WhatsApp Catalog', timestamp: 'Just now', type: 'connection' },
            ...activities
        ]);
    }, 2000);
  };

  return (
    <div className="space-y-8 py-8 animate-in slide-in-from-right duration-300">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
        <div className="flex items-center gap-4">
            <button onClick={onBack} className="p-2 hover:bg-slate-200 rounded-full transition-colors">
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M10 19l-7-7m0 0l7-7m-7 7h18"></path></svg>
            </button>
            <h2 className="text-3xl font-black text-slate-900">Brand HQ Settings</h2>
        </div>

        <div className="flex items-center gap-3 bg-white p-2 rounded-xl border border-slate-200 shadow-sm">
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-widest pl-2">View As:</span>
            <div className="flex gap-1">
                {(['Admin', 'Editor', 'Viewer'] as Role[]).map((r) => (
                    <button
                        key={r}
                        onClick={() => onSwitchRole(r)}
                        className={`px-3 py-1 text-xs font-bold rounded-lg transition-all ${userRole === r ? 'bg-amber-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-100'}`}
                    >
                        {r}
                    </button>
                ))}
            </div>
        </div>
      </div>

      <div className="flex gap-6 border-b border-slate-200 overflow-x-auto no-scrollbar">
        {[
          { id: 'team', label: 'Team', icon: 'M12 4.354a4 4 0 110 5.292M15 21H3v-1a6 6 0 0112 0v1zm0 0h6v-1a6 6 0 00-9-5.197' },
          { id: 'integrations', label: 'Integrations', icon: 'M11 4a2 2 0 114 0v1a2 2 0 01-2 2H3a2 2 0 01-2-2V4a2 2 0 012-2h3a2 2 0 012 2v1a2 2 0 002 2h1a2 2 0 002-2V4z' },
          { id: 'billing', label: 'Billing', icon: 'M3 10h18M7 15h1m4 0h1m-7 4h12a3 3 0 003-3V8a3 3 0 00-3-3H6a3 3 0 00-3 3v8a3 3 0 003 3z' },
          { id: 'help', label: 'Support', icon: 'M8.228 9c.549-1.165 2.03-2 3.772-2 2.21 0 4 1.343 4 3 0 1.4-1.278 2.575-3.006 2.907-.542.104-.994.54-.994 1.093m0 3h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z' }
        ].map((tab) => (
          <button 
              key={tab.id}
              onClick={() => setActiveTab(tab.id as any)}
              className={`pb-4 px-2 font-bold text-sm transition-all flex items-center gap-2 whitespace-nowrap ${activeTab === tab.id ? 'text-amber-600 border-b-2 border-amber-600' : 'text-slate-400 hover:text-slate-600'}`}
          >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d={tab.icon}></path></svg>
              {tab.label}
          </button>
        ))}
      </div>

      {activeTab === 'team' && (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-8">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Team Members</h3>
                    <div className="space-y-4">
                        {members.map(member => (
                            <div key={member.id} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl">
                                <div className="flex items-center gap-4">
                                    <div className="w-10 h-10 bg-amber-100 text-amber-700 rounded-full flex items-center justify-center font-bold text-sm">
                                        {member.avatar}
                                    </div>
                                    <div>
                                        <p className="font-bold text-slate-900 text-sm">{member.name}</p>
                                        <p className="text-xs text-slate-500">{member.email}</p>
                                    </div>
                                </div>
                                <div className="flex items-center gap-4">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wider ${member.role === 'Admin' ? 'bg-purple-100 text-purple-700' : 'bg-blue-100 text-blue-700'}`}>
                                        {member.role}
                                    </span>
                                </div>
                            </div>
                        ))}
                    </div>

                    {userRole === 'Admin' ? (
                        <div className="mt-8 pt-8 border-t border-slate-100">
                            <h4 className="text-sm font-bold text-slate-900 mb-4">Invite New Member</h4>
                            <form onSubmit={handleInvite} className="flex flex-col sm:flex-row gap-4">
                                <input 
                                    type="email" 
                                    placeholder="colleague@agency.com" 
                                    className="flex-1 px-4 py-3 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-amber-500 text-sm"
                                    value={inviteEmail}
                                    onChange={(e) => setInviteEmail(e.target.value)}
                                    required
                                />
                                <button type="submit" className="px-6 py-3 bg-slate-900 text-white rounded-xl font-bold text-sm hover:bg-slate-800 transition-colors">
                                    Send Invite
                                </button>
                            </form>
                        </div>
                    ) : (
                        <div className="mt-8 pt-8 border-t border-slate-100 text-center text-slate-400 text-sm">
                            <p>You must be an Admin to invite new members.</p>
                        </div>
                    )}
                </div>
            </div>

            <div className="lg:col-span-1">
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100 h-full">
                    <h3 className="text-xl font-bold text-slate-900 mb-6">Activity Log</h3>
                    <div className="space-y-6 relative before:absolute before:left-4 before:top-8 before:bottom-0 before:w-0.5 before:bg-slate-100">
                        {activities.map((log) => (
                            <div key={log.id} className="relative pl-10">
                                <div className={`absolute left-2.5 top-1.5 w-3 h-3 rounded-full border-2 border-white shadow-sm ${
                                    log.type === 'creation' ? 'bg-green-500' : 
                                    log.type === 'connection' ? 'bg-blue-500' :
                                    log.type === 'edit' ? 'bg-red-500' :
                                    log.type === 'export' ? 'bg-amber-500' : 'bg-slate-400'
                                }`}></div>
                                <p className="text-xs text-slate-500 mb-1">{log.timestamp}</p>
                                <p className="text-sm font-medium text-slate-900">{log.action}</p>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}

      {activeTab === 'integrations' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Social Accounts</h3>
                {socialAccounts.map(account => (
                    <div key={account.platform} className="bg-white p-6 rounded-[2rem] shadow-sm border border-slate-100 flex items-center justify-between">
                        <div className="flex items-center gap-4">
                            <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white ${
                                account.platform === 'instagram' ? 'bg-gradient-to-tr from-yellow-400 via-red-500 to-purple-500' :
                                account.platform === 'facebook' ? 'bg-blue-600' : 'bg-green-500'
                            }`}>
                                <span>{account.platform.charAt(0).toUpperCase()}</span>
                            </div>
                            <div>
                                <h4 className="font-bold text-slate-900 capitalize">{account.platform}</h4>
                                <p className="text-xs text-slate-500">{account.connected ? 'Connected' : 'Not Connected'}</p>
                            </div>
                        </div>
                        <button className="px-4 py-2 border border-slate-200 rounded-xl text-xs font-bold hover:bg-slate-50 transition-colors">
                            {account.connected ? 'Manage' : 'Connect'}
                        </button>
                    </div>
                ))}
            </div>

            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Commerce & Catalog</h3>
                <div className="bg-white p-8 rounded-[2rem] shadow-sm border border-slate-100">
                    <div className="flex items-center gap-4 mb-6">
                        <div className="w-12 h-12 bg-green-100 text-green-600 rounded-xl flex items-center justify-center">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M16 11V7a4 4 0 00-8 0v4M5 9h14l1 12H4L5 9z"></path></svg>
                        </div>
                        <div>
                            <h4 className="font-bold text-slate-900">WhatsApp Catalog</h4>
                            <p className="text-xs text-slate-500">{catalogSynced ? `Synced: ${products.length} Products` : 'Sync Required'}</p>
                        </div>
                    </div>

                    <button 
                        onClick={handleSyncCatalog}
                        disabled={isSyncing}
                        className="w-full py-3 bg-green-600 text-white rounded-xl font-bold text-sm shadow-lg hover:bg-green-700 transition-all disabled:opacity-70 flex items-center justify-center gap-2 mb-6"
                    >
                        {isSyncing ? 'Syncing...' : 'Sync Catalog Now'}
                    </button>

                    <div className="space-y-3">
                        <h5 className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Inventory Preview</h5>
                        {products.slice(0, 3).map(p => (
                            <div key={p.id} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-xl transition-colors">
                                <img src={p.imageUrl} alt={p.name} className="w-10 h-10 rounded-lg object-cover" />
                                <div className="flex-1">
                                    <p className="text-[11px] font-bold text-slate-900">{p.name}</p>
                                    <p className="text-[10px] text-slate-500">{p.price}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </div>
        </div>
      )}

      {activeTab === 'billing' && (
        <div className="space-y-8">
            <div className="bg-brand-950 rounded-[2.5rem] p-10 text-white relative overflow-hidden">
                <div className="absolute top-0 right-0 w-64 h-64 bg-brand-600 rounded-full blur-[100px] opacity-20 -mr-20 -mt-20"></div>
                <div className="relative z-10 flex flex-col md:flex-row justify-between items-start md:items-center gap-8">
                    <div className="space-y-4">
                        <span className="px-3 py-1 bg-brand-600 rounded-full text-[10px] font-black uppercase tracking-widest">Active Plan</span>
                        <h3 className="text-4xl font-black tracking-tight">Afri-Pro <span className="text-brand-500">Plan</span></h3>
                        <p className="text-slate-400 font-medium">Next renewal: March 12, 2025 • 15 000 FCFA</p>
                    </div>
                    <button className="px-8 py-4 bg-white text-brand-950 rounded-2xl font-bold text-sm shadow-xl hover:bg-slate-100 transition-all">Manage Subscription</button>
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
                {[
                    { label: 'Images Generated', value: '42 / 150', progress: 28 },
                    { label: 'Video Ads (Veo)', value: '3 / 10', progress: 30 },
                    { label: 'DNA Refinements', value: 'Unlimited', progress: 100 }
                ].map((stat, i) => (
                    <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm space-y-4">
                        <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">{stat.label}</p>
                        <div className="flex items-baseline justify-between">
                            <span className="text-2xl font-black text-slate-900">{stat.value}</span>
                        </div>
                        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                            <div className="h-full bg-brand-600" style={{ width: `${stat.progress}%` }}></div>
                        </div>
                    </div>
                ))}
            </div>

            <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
                <div className="px-8 py-6 border-b border-slate-100 flex justify-between items-center">
                    <h4 className="font-black text-slate-900">Recent Invoices</h4>
                    <button className="text-[10px] font-black text-brand-600 uppercase tracking-widest">View All</button>
                </div>
                <div className="divide-y divide-slate-50">
                    {[
                        { date: 'Feb 12, 2025', id: 'INV-9021', amount: '15 000 FCFA', status: 'Paid' },
                        { date: 'Jan 12, 2025', id: 'INV-8812', amount: '15 000 FCFA', status: 'Paid' }
                    ].map((inv, i) => (
                        <div key={i} className="px-8 py-4 flex justify-between items-center hover:bg-slate-50 transition-colors">
                            <div className="flex gap-4 items-center">
                                <div className="w-10 h-10 bg-slate-100 rounded-xl flex items-center justify-center text-slate-500">
                                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z"></path></svg>
                                </div>
                                <div>
                                    <p className="text-sm font-bold text-slate-900">{inv.id}</p>
                                    <p className="text-xs text-slate-500">{inv.date}</p>
                                </div>
                            </div>
                            <div className="text-right">
                                <p className="text-sm font-black text-slate-900">{inv.amount}</p>
                                <span className="text-[9px] font-black text-green-600 uppercase tracking-widest">{inv.status}</span>
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        </div>
      )}

      {activeTab === 'help' && (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Help Center</h3>
                <div className="space-y-4">
                    {[
                        { q: "Comment fonctionne l'IA culturelle ?", a: "AfriBrand AI utilise des modèles Gemini entraînés sur des lexiques locaux (Nouchi, Wolof, etc.) pour garantir que vos textes sonnent authentiquement." },
                        { q: "Puis-je changer mon ADN de marque ?", a: "Oui, à tout moment dans l'onglet 'DNA'. Vos futurs contenus s'adapteront instantanément à la nouvelle identité." },
                        { q: "Quels sont les délais de génération vidéo ?", a: "Le mode 'Fast' prend environ 1 à 2 minutes. Le mode 'High-Quality' peut prendre jusqu'à 5 minutes." }
                    ].map((item, i) => (
                        <div key={i} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm space-y-2">
                            <h4 className="font-bold text-slate-900 text-sm">{item.q}</h4>
                            <p className="text-xs text-slate-500 leading-relaxed font-medium">{item.a}</p>
                        </div>
                    ))}
                </div>
            </div>

            <div className="space-y-6">
                <h3 className="text-xl font-bold text-slate-900">Contact Support</h3>
                <div className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm space-y-6">
                    <p className="text-sm text-slate-500 font-medium">Besoin d'aide personnalisée ? Nos experts marketing sont là pour vous.</p>
                    <div className="space-y-4">
                        <button className="w-full py-4 bg-brand-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:bg-brand-500 transition-all flex items-center justify-center gap-3">
                            <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 12h.01M12 12h.01M16 12h.01M21 12c0 4.418-4.03 8-9 8a9.863 9.863 0 01-4.255-.949L3 20l1.395-3.72C3.512 15.042 3 13.574 3 12c0-4.418 4.03-8 9-8s9 3.582 9 8z"></path></svg>
                            Live WhatsApp Chat
                        </button>
                        <button className="w-full py-4 border-2 border-slate-100 text-slate-600 rounded-2xl font-bold text-sm hover:bg-slate-50 transition-all">
                            Submit a Ticket
                        </button>
                    </div>
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

export default BrandSettings;
